#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct LatencySample {
    pub timestamp_sec: u64,
    pub duration_ms: u64,
}

#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct LatencyTracker {
    events: HashMap<String, VecDeque<LatencySample>>,
    pub threshold_ms: u64,
}

impl LatencyTracker {
    const MAX_SAMPLES_PER_EVENT: usize = 160;

    pub fn record_sample(&mut self, event: &str, duration_ms: u64, now_sec: u64) {
        let samples = self.events.entry(event.to_string()).or_default();
        samples.push_back(LatencySample {
            timestamp_sec: now_sec,
            duration_ms,
        });
        while samples.len() > Self::MAX_SAMPLES_PER_EVENT {
            samples.pop_front();
        }
    }

    #[must_use]
    pub fn latest(&self) -> Vec<(String, LatencySample)> {
        let mut latest: Vec<(String, LatencySample)> = self
            .events
            .iter()
            .filter_map(|(event, samples)| {
                samples
                    .back()
                    .copied()
                    .map(|sample| (event.clone(), sample))
            })
            .collect();
        latest.sort_by(|left, right| left.0.cmp(&right.0));
        latest
    }

    #[must_use]
    pub fn history(&self, event: &str) -> Vec<LatencySample> {
        self.events
            .get(event)
            .map(|samples| samples.iter().copied().collect())
            .unwrap_or_default()
    }

    pub fn reset(&mut self, events: &[&str]) -> usize {
        if events.is_empty() {
            let count = self.events.len();
            self.events.clear();
            return count;
        }

        events
            .iter()
            .filter(|event| self.events.remove(**event).is_some())
            .count()
    }
}

/// Per-command latency histogram using power-of-2 microsecond buckets.
/// Buckets: [0, 1), [1, 2), [2, 4), [4, 8), ..., [2^22, 2^23), [2^23, ∞)
/// This gives ~8 second max tracked latency with 24 buckets.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct CommandHistogram {
    /// Bucket counts: bucket[i] covers [2^(i-1), 2^i) microseconds, except bucket[0] is [0, 1).
    buckets: [u64; 24],
    /// Total number of calls recorded (success + failed; matches upstream's `calls` field).
    pub calls: u64,
    /// Sum of latencies in microseconds for all recorded calls.
    /// (frankenredis-infosections) Mirrors upstream redisCommand::microseconds —
    /// emitted as the `usec` column of INFO commandstats.
    pub total_usec: u64,
    /// Calls that were rejected before reaching the handler (wrong arity, ACL deny,
    /// NOSCRIPT, NOAUTH, NOPERM, etc.). (frankenredis-infosections)
    pub rejected_calls: u64,
    /// Calls that ran but returned an error reply. (frankenredis-infosections)
    pub failed_calls: u64,
}

/// Outcome classification for `CommandHistogram::record`. Drives the
/// upstream `calls`/`rejected_calls`/`failed_calls` counters separately
/// so `cmdstat_<cmd>` lines mirror server.c::genRedisInfoStringCommandStats.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum CommandRecordKind {
    /// Handler ran and returned a non-error reply.
    Success,
    /// Pre-handler rejection (wrong arity, ACL deny, NOSCRIPT, NOAUTH, NOPERM, ...).
    /// Rejected calls do NOT increment the `calls`/`total_usec` columns; they are
    /// counted only in `rejected_calls` per upstream's call() / processCommand().
    Rejected,
    /// Handler ran but returned an error reply.
    Failed,
}

impl CommandHistogram {
    /// Record a latency sample in microseconds.
    /// (frankenredis-infosections) Convenience wrapper for the common
    /// success path; equivalent to record_with_kind(latency_us, Success).
    pub fn record(&mut self, latency_us: u64) {
        self.record_with_kind(latency_us, CommandRecordKind::Success);
    }

    /// Record a latency sample in microseconds with an explicit outcome.
    pub fn record_with_kind(&mut self, latency_us: u64, kind: CommandRecordKind) {
        match kind {
            CommandRecordKind::Rejected => {
                // Upstream's call() does NOT call durationAdd or
                // bump `calls` for rejected commands — only the
                // rejected counter moves. Mirror that semantics.
                self.rejected_calls += 1;
                return;
            }
            CommandRecordKind::Failed => {
                self.failed_calls += 1;
            }
            CommandRecordKind::Success => {}
        }
        self.calls += 1;
        self.total_usec = self.total_usec.saturating_add(latency_us);
        let bucket_idx = if latency_us == 0 {
            0
        } else {
            // Find the bucket: bucket i covers [2^(i-1), 2^i) for i > 0
            // Use leading zeros to find log2
            let log2 = 63_u32.saturating_sub(latency_us.leading_zeros());
            // Bucket 0 is [0,1), bucket 1 is [1,2), bucket 2 is [2,4), etc.
            // So bucket index = log2 + 1, clamped to 23 max
            (log2 + 1).min(23) as usize
        };
        self.buckets[bucket_idx] += 1;
    }

    /// Get histogram data as (bucket_start_us, count) pairs for non-zero buckets.
    #[must_use]
    pub fn to_buckets(&self) -> Vec<(u64, u64)> {
        self.buckets
            .iter()
            .enumerate()
            .filter(|&(_, count)| *count > 0)
            .map(|(i, count)| {
                let start_us = if i == 0 { 0 } else { 1_u64 << (i - 1) };
                (start_us, *count)
            })
            .collect()
    }

    /// Reset the histogram.
    pub fn reset(&mut self) {
        self.buckets = [0; 24];
        self.calls = 0;
        self.total_usec = 0;
        self.rejected_calls = 0;
        self.failed_calls = 0;
    }
}

/// Tracks per-command latency histograms.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct CommandHistogramTracker {
    get: Option<CommandHistogram>,
    set: Option<CommandHistogram>,
    histograms: HashMap<String, CommandHistogram, foldhash::quality::RandomState>,
}

impl CommandHistogramTracker {
    /// Record a successful command latency in microseconds.
    /// (frankenredis-infosections) Convenience wrapper that classifies
    /// the call as a Success outcome; new code should prefer
    /// `record_with_kind` so rejected/failed counters move.
    pub fn record(&mut self, command: &str, latency_us: u64) {
        self.record_with_kind(command, latency_us, CommandRecordKind::Success);
    }

    /// Record a command latency with an explicit outcome classification.
    pub fn record_with_kind(&mut self, command: &str, latency_us: u64, kind: CommandRecordKind) {
        // (frankenredis-6n2qm) Upstream canonicalises command names to
        // their lowercase commands.def form (`cmd->fullname`) before
        // updating the per-command histogram. fr previously upper-cased
        // the key, so callers like LATENCY HISTOGRAM and INFO
        // Latencystats emitted UPPERCASE rows when the user happened
        // to send commands uppercase, breaking grep parity with
        // vendored. INFO Commandstats already lowercased on emission,
        // masking the bug for that one path.
        //
        // (frankenredis-igx7w) This runs on every command, so avoid the
        // per-command heap allocation of `to_ascii_lowercase()`: lowercase the
        // name into a stack buffer and probe the existing entry (the common
        // case) without allocating, paying the owned-key allocation only on the
        // first occurrence of each command. Command names are short ASCII; the
        // rare longer name (e.g. an attacker's unknown command) takes the heap
        // path. Byte-identical canonical key in all cases.
        let bytes = command.as_bytes();
        if bytes.len() <= 40 {
            let mut buf = [0u8; 40];
            let lower = &mut buf[..bytes.len()];
            for (dst, &src) in lower.iter_mut().zip(bytes) {
                *dst = src.to_ascii_lowercase();
            }
            // ASCII-lowercasing valid UTF-8 yields valid UTF-8 (only A-Z change,
            // both ASCII), so this never fails.
            if let Ok(key) = std::str::from_utf8(lower) {
                self.record_canonical_with_kind(key, latency_us, kind);
                return;
            }
        }
        let key = command.to_ascii_lowercase();
        self.record_canonical_with_kind(&key, latency_us, kind);
    }

    fn record_canonical_with_kind(
        &mut self,
        command: &str,
        latency_us: u64,
        kind: CommandRecordKind,
    ) {
        if command == "get" {
            self.get
                .get_or_insert_with(CommandHistogram::default)
                .record_with_kind(latency_us, kind);
            return;
        }
        if command == "set" {
            self.set
                .get_or_insert_with(CommandHistogram::default)
                .record_with_kind(latency_us, kind);
            return;
        }
        self.histograms
            .entry(command.to_string())
            .or_default()
            .record_with_kind(latency_us, kind);
    }

    /// Get histogram for a specific command.
    #[must_use]
    pub fn get(&self, command: &str) -> Option<&CommandHistogram> {
        let key = command.to_ascii_lowercase();
        if key == "get" {
            return self.get.as_ref();
        }
        if key == "set" {
            return self.set.as_ref();
        }
        self.histograms.get(&key)
    }

    /// Get all histograms, sorted by command name.
    #[must_use]
    pub fn all(&self) -> Vec<(&str, &CommandHistogram)> {
        let mut result: Vec<_> = self
            .histograms
            .iter()
            .map(|(k, v)| (k.as_str(), v))
            .collect();
        if let Some(hist) = &self.get {
            result.push(("get", hist));
        }
        if let Some(hist) = &self.set {
            result.push(("set", hist));
        }
        result.sort_by(|a, b| a.0.cmp(b.0));
        result
    }

    /// Reset histograms for specified commands, or all if empty.
    pub fn reset(&mut self, commands: &[&str]) -> usize {
        if commands.is_empty() {
            let count = self.histograms.len()
                + usize::from(self.get.is_some())
                + usize::from(self.set.is_some());
            self.get = None;
            self.set = None;
            self.histograms.clear();
            return count;
        }
        commands
            .iter()
            .filter_map(|cmd| {
                // (frankenredis-6n2qm) Lookup key matches the
                // canonical lowercase form used by record_with_kind.
                let key = cmd.to_ascii_lowercase();
                if key == "get" {
                    return self.get.as_mut().map(|h| {
                        h.reset();
                        1
                    });
                }
                if key == "set" {
                    return self.set.as_mut().map(|h| {
                        h.reset();
                        1
                    });
                }
                self.histograms.get_mut(&key).map(|h| {
                    h.reset();
                    1
                })
            })
            .sum()
    }
}

