#[derive(Clone, Debug, PartialEq, Eq)]
pub struct DispatchClientContext {
    pub client_id: u64,
    pub client_name: Option<Vec<u8>>,
    pub client_lib_name: Option<String>,
    pub client_lib_ver: Option<String>,
    pub age_seconds: u64,
    pub idle_seconds: u64,
    pub db_index: usize,
    pub flags: String,
    pub peer_addr: String,
    /// (frankenredis-lxccd) Real socket fd when the dispatch context
    /// belongs to a TCP-accepted client. Mirrored from
    /// ClientSession::socket_fd by the runtime when constructing the
    /// dispatch context.
    pub socket_fd: Option<i32>,
    /// (frankenredis-tepuj) Per-client read-buffer accounting fields
    /// mirrored from ClientSession by the runtime when constructing the
    /// dispatch context. `qbuf_bytes` is the live read-buffer length;
    /// `qbuf_free_bytes` is the trailing free capacity; `output_buffer_bytes`
    /// is the live write-buffer length. These power CLIENT INFO's
    /// `qbuf=`, `qbuf-free=`, `obl=`, and `tot-mem=` fields so dashboards
    /// diffing against vendored 7.2 see non-zero buffer metrics.
    pub qbuf_bytes: usize,
    pub qbuf_free_bytes: usize,
    pub output_buffer_bytes: usize,
    pub authenticated_user: Vec<u8>,
    pub resp_protocol_version: i64,
    pub channel_subscriptions: usize,
    pub pattern_subscriptions: usize,
    pub shard_subscriptions: usize,
    pub multi_count: i64,
    pub watch_count: usize,
    pub is_pubsub: bool,
    pub client_tracking: ClientTrackingState,
    pub client_reply: ClientReplyState,
    /// Mirrors the per-session CLIENT NO-EVICT flag so dispatch_argv
    /// callers (Lua / AOF replay / MULTI EXEC) can update session
    /// state through the runtime sync-back. (frankenredis-qteu5)
    pub client_no_evict: bool,
    /// Mirrors the per-session CLIENT NO-TOUCH flag, same pattern.
    pub client_no_touch: bool,
    /// Runtime-mediated top-level commands already passed the runtime ACL gate
    /// before dispatching into fr-command. Direct command-crate callers and
    /// nested script calls leave this false so dispatch_argv still enforces ACL.
    pub acl_checked_by_runtime: bool,
    pub acl_permissions: Option<DispatchAclPermissions>,
    /// (frankenredis-ax9ox) True when MONITOR clients are attached, mirrored by
    /// the runtime per dispatch. Lets nested script (`redis.call`) execution
    /// cheaply gate recording each inner command for the MONITOR `lua` feed —
    /// no per-call clone when nobody is monitoring.
    pub monitors_active: bool,
}

impl Default for DispatchClientContext {
    fn default() -> Self {
        Self {
            client_id: 1,
            client_name: None,
            client_lib_name: None,
            client_lib_ver: None,
            age_seconds: 0,
            idle_seconds: 0,
            db_index: 0,
            flags: "N".to_string(),
            peer_addr: "127.0.0.1:0".to_string(),
            socket_fd: None,
            qbuf_bytes: 0,
            qbuf_free_bytes: 0,
            output_buffer_bytes: 0,
            authenticated_user: b"default".to_vec(),
            resp_protocol_version: 2,
            channel_subscriptions: 0,
            pattern_subscriptions: 0,
            shard_subscriptions: 0,
            multi_count: -1,
            watch_count: 0,
            is_pubsub: false,
            client_tracking: ClientTrackingState::default(),
            client_reply: ClientReplyState::default(),
            client_no_evict: false,
            client_no_touch: false,
            acl_checked_by_runtime: false,
            acl_permissions: None,
            monitors_active: false,
        }
    }
}

