    pub fn hmget(
        &mut self,
        key: &[u8],
        fields: &[&[u8]],
        now_ms: u64,
    ) -> Result<Vec<Option<Vec<u8>>>, StoreError> {
        if !self.record_keyspace_lookup(key, now_ms) {
            return Ok(fields.iter().map(|_| None).collect());
        }
        for field in fields {
            self.drop_hash_field_if_expired(key, field, now_ms);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                entry.touch(now_ms);
                match &entry.value {
                    Value::Hash(m) => Ok(fields
                        .iter()
                        .map(|f| m.get(f).map(<[u8]>::to_vec))
                        .collect()),
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(fields.iter().map(|_| None).collect()),
        }
    }

    pub fn hincrby(
        &mut self,
        key: &[u8],
        field: &[u8],
        delta: i64,
        now_ms: u64,
    ) -> Result<i64, StoreError> {
        self.drop_if_expired(key, now_ms);
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let should_bump_lfu = lfu_tracking_enabled && self.entries.contains_key(key);
        let rand_sample = if should_bump_lfu { self.next_rand() } else { 0 };
        self.internal_entry(key.to_vec(), Value::Hash(Box::default()), now_ms);
        let max_entries = self.hash_max_listpack_entries;
        let max_value = self.hash_max_listpack_value;
        let (res, is_empty) = self
            .with_mutated_entry(key, |entry| {
                if should_bump_lfu {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                let Value::Hash(m) = &mut entry.value else {
                    return (Err(StoreError::WrongType), false);
                };
                let mut touched = false;
                let current_res = match m.get(field) {
                    Some(v) => parse_i64(v).map_err(|_| StoreError::HashValueNotInteger),
                    None => Ok(0),
                };
                let res = match current_res {
                    Ok(current) => match current.checked_add(delta) {
                        Some(next) => {
                            m.insert(field.to_vec(), next.to_string().into_bytes());
                            touched = true;
                            Ok(next)
                        }
                        None => Err(StoreError::IntegerOverflow),
                    },
                    Err(e) => Err(e),
                };
                let is_empty = m.is_empty();
                if touched {
                    entry.touch_write(now_ms);
                    // (frankenredis-yp503) Crossing the entries count via
                    // hincrby on a new field can promote to hashtable.
                    Self::refresh_hash_encoding_flag(entry, max_entries, max_value);
                }
                (res, is_empty)
            })
            .expect("hash entry was ensured");
        if res.is_ok() {
            self.dirty = self.dirty.saturating_add(1);
        }
        if is_empty {
            self.internal_entries_remove(key);
        }
        res
    }

    pub fn hsetnx(
        &mut self,
        key: &[u8],
        field: Vec<u8>,
        value: Vec<u8>,
        now_ms: u64,
    ) -> Result<bool, StoreError> {
        self.drop_if_expired(key, now_ms);
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let should_bump_lfu = lfu_tracking_enabled && self.entries.contains_key(key);
        let rand_sample = if should_bump_lfu { self.next_rand() } else { 0 };
        self.internal_entry(key.to_vec(), Value::Hash(Box::default()), now_ms);
        let max_entries = self.hash_max_listpack_entries;
        let max_value = self.hash_max_listpack_value;
        let result = self
            .with_mutated_entry(key, |entry| {
                if should_bump_lfu {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                let Value::Hash(m) = &mut entry.value else {
                    return Err(StoreError::WrongType);
                };
                if !m.contains_key(&field) {
                    m.insert(field, value);
                    entry.touch_write(now_ms);
                    // (frankenredis-yp503) Lock hashtable encoding if
                    // threshold crossed.
                    Self::refresh_hash_encoding_flag(entry, max_entries, max_value);
                    Ok(true)
                } else {
                    Ok(false)
                }
            })
            .expect("hash entry was ensured");
        if matches!(result, Ok(true)) {
            self.dirty = self.dirty.saturating_add(1);
        }
        result
    }

