    /// Return elements sorted ascending by score, by index range.
    pub fn zrange(
        &mut self,
        key: &[u8],
        start: i64,
        stop: i64,
        now_ms: u64,
    ) -> Result<Vec<Vec<u8>>, StoreError> {
        if !self.record_keyspace_lookup(key, now_ms) {
            return Ok(Vec::new());
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::SortedSet(zs) => {
                        let len = zs.len() as i64;
                        let s = normalize_index(start, len);
                        let e = normalize_index(stop, len);
                        if s > e || s >= len || e < 0 {
                            return Ok(Vec::new());
                        }
                        let s_idx = s.max(0) as usize;
                        let e_idx = e.min(len - 1) as usize;
                        let count = e_idx - s_idx + 1;
                        let result: Vec<Vec<u8>> = zs
                            .index_slice_asc(s_idx, count)
                            .into_iter()
                            .map(|(m, _)| m)
                            .collect();
                        entry.touch(now_ms);
                        Ok(result)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(Vec::new()),
        }
    }

