/// Convert a Redis-style index (negative = from end) to a `usize`.
/// Read `bits` bits starting at `bit_offset` from a byte slice (MSB-first bit ordering).
/// Returns the value as i64. If `signed`, sign-extends from the field width.
fn bitfield_read(bytes: &[u8], bit_offset: u64, bits: u8, signed: bool) -> i64 {
    if bits == 0 {
        return 0;
    }
    let mut value: u64 = 0;
    for b in 0..u64::from(bits) {
        let pos = bit_offset.wrapping_add(b);
        let byte_idx = (pos / 8) as usize;
        let bit_idx = 7 - (pos % 8) as u8;
        let bit_val = if byte_idx < bytes.len() {
            (bytes[byte_idx] >> bit_idx) & 1
        } else {
            0
        };
        value = (value << 1) | u64::from(bit_val);
    }
    if signed && bits < 64 {
        // Sign-extend: if the MSB of the field is set, fill upper bits with 1s
        let sign_bit = 1u64 << (bits - 1);
        if value & sign_bit != 0 {
            let mask = u64::MAX << bits;
            value |= mask;
        }
    }
    value as i64
}

/// Write `bits` bits of `value` starting at `bit_offset` in a byte slice (MSB-first).
/// The byte slice must already be large enough to hold the write.
fn bitfield_write(bytes: &mut [u8], bit_offset: u64, bits: u8, value: i64) {
    let value = value as u64;
    for b in 0..u64::from(bits) {
        let pos = bit_offset.wrapping_add(b);
        let byte_idx = (pos / 8) as usize;
        let bit_idx = 7 - (pos % 8) as u8;
        // Extract the bit from value (MSB of the field first)
        let bit_pos = (bits as u64) - 1 - b;
        let bit_val = (value >> bit_pos) & 1;
        if bit_val == 1 {
            bytes[byte_idx] |= 1 << bit_idx;
        } else {
            bytes[byte_idx] &= !(1 << bit_idx);
        }
    }
}

fn normalize_index(index: i64, len: i64) -> i64 {
    if index < 0 {
        len.saturating_add(index)
    } else {
        index
    }
}

fn canonicalize_zero_score(score: f64) -> f64 {
    if score == 0.0 { 0.0 } else { score }
}

/// Check if a member falls within a lex range.
/// Redis lex range format: `-` = neg infinity, `+` = pos infinity,
/// `[value` = inclusive, `(value` = exclusive.
fn lex_in_range(member: &[u8], min: &[u8], max: &[u8]) -> bool {
    let above_min = if min == b"-" {
        true
    } else if min == b"+" {
        // Positive infinity as the MIN bound: nothing is at or above it.
        false
    } else if min.starts_with(b"(") {
        member > &min[1..]
    } else if min.starts_with(b"[") {
        member >= &min[1..]
    } else {
        member >= min
    };
    let below_max = if max == b"+" {
        true
    } else if max == b"-" {
        // Negative infinity as the MAX bound: nothing is at or below it.
        false
    } else if max.starts_with(b"(") {
        member < &max[1..]
    } else if max.starts_with(b"[") {
        member <= &max[1..]
    } else {
        member <= max
    };
    above_min && below_max
}

fn validate_lex_range_bounds(min: &[u8], max: &[u8]) -> Result<(), StoreError> {
    if is_valid_lex_bound(min) && is_valid_lex_bound(max) {
        Ok(())
    } else {
        Err(invalid_lex_range_error())
    }
}

fn is_valid_lex_bound(bound: &[u8]) -> bool {
    bound == b"-" || bound == b"+" || bound.first().is_some_and(|c| *c == b'[' || *c == b'(')
}

fn invalid_lex_range_error() -> StoreError {
    StoreError::GenericError("ERR min or max not valid string range item".to_string())
}

// ── HyperLogLog internals ─────────────────────────────────────────────

const HLL_P: u32 = 14;
const HLL_REGISTERS: usize = 1 << HLL_P; // 16384
// (frankenredis-2bpzv) Constants for the Otmar Ertl 2017 cardinality estimator
// (redis hyperloglog.c::hllCount), matching upstream byte-for-byte.
const HLL_Q: usize = 64 - HLL_P as usize; // 50 — max rho the hash can yield is HLL_Q+1
// 0.5/ln(2). Shortest decimal that round-trips to the exact same f64 as
// upstream's `0.721347520444481703680`, so the estimate is bit-identical.
const HLL_ALPHA_INF: f64 = 0.7213475204444817;
const HLL_REDIS_MAGIC: &[u8] = b"HYLL";
const HLL_MAGIC_V2: &[u8] = b"HYL2";
const HLL_HEADER_SIZE: usize = HLL_MAGIC_V2.len() + 1;
const HLL_DATA_SIZE: usize = HLL_HEADER_SIZE + HLL_REGISTERS; // 16389
const HLL_LEGACY_DATA_SIZE: usize = HLL_REDIS_MAGIC.len() + HLL_REGISTERS; // 16388
const HLL_REDIS_HEADER_SIZE: usize = 16;
const HLL_REDIS_DENSE_REGISTER_BYTES: usize = (HLL_REGISTERS * 6).div_ceil(8);
const HLL_REDIS_DENSE_SIZE: usize = HLL_REDIS_HEADER_SIZE + HLL_REDIS_DENSE_REGISTER_BYTES;
const HLL_REDIS_DENSE_ENCODING: u8 = 0;
const HLL_REDIS_SPARSE_ENCODING: u8 = 1;
const HLL_SPARSE_XZERO_BIT: u8 = 0x40;
const HLL_SPARSE_VAL_BIT: u8 = 0x80;
const HLL_SPARSE_VAL_MAX_VALUE: u8 = 32;
const HLL_SPARSE_VAL_MAX_LEN: usize = 4;
const HLL_SPARSE_ZERO_MAX_LEN: usize = 64;
const HLL_SPARSE_XZERO_MAX_LEN: usize = 16_384;
const HLL_REDIS_SPARSE_MAX_BYTES: usize = 3_000;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum HllEncoding {
    Sparse,
    Dense,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum HllSparseOpcode {
    Zero(usize),
    XZero(usize),
    Val { value: u8, len: usize },
}

impl HllEncoding {
    fn from_byte(byte: u8) -> Option<Self> {
        match byte {
            0 => Some(Self::Sparse),
            1 => Some(Self::Dense),
            _ => None,
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::Sparse => "sparse",
            Self::Dense => "dense",
        }
    }
}

/// MurmurHash64A-style hash for HyperLogLog element hashing.
/// HyperLogLog accuracy depends on good bit dispersion; the earlier FNV-based
/// implementation produced materially worse estimator error at moderate
/// cardinalities.
fn hll_hash(data: &[u8]) -> u64 {
    const M: u64 = 0xc6a4_a793_5bd1_e995;
    const R: u32 = 47;

    let len = data.len() as u64;
    let mut h = 0xadc8_3b19_u64 ^ len.wrapping_mul(M);

    let mut chunks = data.chunks_exact(8);
    for chunk in &mut chunks {
        let mut k_bytes = [0u8; 8];
        k_bytes.copy_from_slice(chunk);
        let mut k = u64::from_le_bytes(k_bytes);
        k = k.wrapping_mul(M);
        k ^= k >> R;
        k = k.wrapping_mul(M);

        h ^= k;
        h = h.wrapping_mul(M);
    }

    let tail = chunks.remainder();
    if !tail.is_empty() {
        let mut remaining = 0_u64;
        for (shift, byte) in tail.iter().enumerate() {
            remaining |= u64::from(*byte) << (shift * 8);
        }
        h ^= remaining;
        h = h.wrapping_mul(M);
    }

    h ^= h >> R;
    h = h.wrapping_mul(M);
    h ^ (h >> R)
}

/// Position of the leftmost 1-bit in a `(64 - HLL_P)`-bit value, counting from 1.
/// Returns `64 - HLL_P + 1` when `w == 0` (all zeros).
fn hll_rho(w: u64) -> u8 {
    let width = 64 - HLL_P; // 50
    if w == 0 {
        return (width + 1) as u8;
    }
    let tz = w.trailing_zeros();
    (tz + 1) as u8
}

fn hll_parse(data: &[u8], mode: HllDecode) -> Result<(HllEncoding, Vec<u8>), StoreError> {
    if data.starts_with(HLL_REDIS_MAGIC) {
        let Some(&encoding) = data.get(HLL_REDIS_MAGIC.len()) else {
            return Err(StoreError::InvalidHllValue);
        };
        match encoding {
            HLL_REDIS_DENSE_ENCODING if data.len() == HLL_REDIS_DENSE_SIZE => {
                return Ok((
                    HllEncoding::Dense,
                    hll_decode_dense_registers(&data[HLL_REDIS_HEADER_SIZE..])?,
                ));
            }
            HLL_REDIS_SPARSE_ENCODING if data.len() >= HLL_REDIS_HEADER_SIZE => {
                return Ok((
                    HllEncoding::Sparse,
                    hll_decode_sparse_registers(&data[HLL_REDIS_HEADER_SIZE..], mode)?,
                ));
            }
            _ => {}
        }
        if data.len() == HLL_LEGACY_DATA_SIZE {
            return Ok((HllEncoding::Dense, data[HLL_REDIS_MAGIC.len()..].to_vec()));
        }
        return Err(StoreError::InvalidHllValue);
    }
    if data.len() == HLL_DATA_SIZE && data.starts_with(HLL_MAGIC_V2) {
        let encoding =
            HllEncoding::from_byte(data[HLL_MAGIC_V2.len()]).ok_or(StoreError::InvalidHllValue)?;
        return Ok((encoding, data[HLL_HEADER_SIZE..].to_vec()));
    }
    Err(StoreError::InvalidHllValue)
}

fn hll_parse_registers(data: &[u8], mode: HllDecode) -> Result<Vec<u8>, StoreError> {
    hll_parse(data, mode).map(|(_, registers)| registers)
}

/// True when `data` is the Redis HLL serialization — `HYLL` magic plus a
/// 16-byte header whose trailing 8 bytes carry the cardinality cache — as
/// opposed to the header-less legacy form or fr's internal `HYL2` form.
/// (frankenredis-twdut)
fn hll_has_redis_cache_header(data: &[u8]) -> bool {
    data.starts_with(HLL_REDIS_MAGIC)
        && data.len() >= HLL_REDIS_HEADER_SIZE
        && data.len() != HLL_LEGACY_DATA_SIZE
}

/// O(1) structural validation of a Redis HLL header, mirroring upstream
/// `hyperloglog.c::isHLLObjectOrReply`: magic `HYLL`, a header of at least 16
/// bytes, an encoding byte of 0 (dense) or 1 (sparse), and — for the dense
/// encoding — a string length that exactly matches the dense register payload.
/// The caller must ensure `data` carries the Redis cache-header form
/// (`hll_has_redis_cache_header`). This guards the cardinality-cache fast path:
/// upstream validates the object BEFORE reading the cache, so a `HYLL` string
/// with a bogus encoding/length surfaces WRONGTYPE rather than a stale cache.
/// (frankenredis-hllval)
fn hll_redis_header_is_valid(data: &[u8]) -> bool {
    let Some(&encoding) = data.get(HLL_REDIS_MAGIC.len()) else {
        return false;
    };
    if encoding > HLL_REDIS_SPARSE_ENCODING {
        return false;
    }
    if encoding == HLL_REDIS_DENSE_ENCODING && data.len() != HLL_REDIS_DENSE_SIZE {
        return false;
    }
    true
}

/// Read the cached cardinality from a Redis HLL header when it is valid (the
/// high bit of the last cache byte is clear). Returns `None` when the cache
/// has been invalidated by a modification or the value isn't in the Redis
/// 16-byte-header form. Mirrors upstream `HLL_VALID_CACHE`. (frankenredis-twdut)
fn hll_cache_read(data: &[u8]) -> Option<u64> {
    if !hll_has_redis_cache_header(data) {
        return None;
    }
    let card: [u8; 8] = data[8..16].try_into().ok()?;
    if card[7] & 0x80 != 0 {
        return None; // HLL_INVALIDATE_CACHE bit set
    }
    Some(u64::from_le_bytes(card))
}

/// Store `card` into the Redis HLL header cache, clearing the invalid bit.
/// Returns whether the value carried a Redis header to update. Cardinalities
/// fit far below 2^56, so the little-endian value's top "invalid" bit is
/// naturally 0. Mirrors upstream which writes `card[0..8]` and clears
/// `HLL_INVALIDATE_CACHE`. (frankenredis-twdut)
fn hll_cache_write(data: &mut [u8], card: u64) -> bool {
    if !hll_has_redis_cache_header(data) {
        return false;
    }
    data[8..16].copy_from_slice(&card.to_le_bytes());
    true
}

fn hll_encode(registers: &[u8], encoding: HllEncoding) -> Vec<u8> {
    let mut data = Vec::new();
    data.extend_from_slice(HLL_REDIS_MAGIC);
    data.push(match encoding {
        HllEncoding::Dense => HLL_REDIS_DENSE_ENCODING,
        HllEncoding::Sparse => HLL_REDIS_SPARSE_ENCODING,
    });
    data.extend_from_slice(&[0, 0, 0]);
    data.extend_from_slice(&[0, 0, 0, 0, 0, 0, 0, 0x80]);
    match encoding {
        HllEncoding::Dense => data.extend_from_slice(&hll_encode_dense_registers(registers)),
        HllEncoding::Sparse => {
            if let Some(encoded) = hll_encode_sparse_registers(registers) {
                data.extend_from_slice(&encoded);
            } else {
                data[HLL_REDIS_MAGIC.len()] = HLL_REDIS_DENSE_ENCODING;
                data.extend_from_slice(&hll_encode_dense_registers(registers));
            }
        }
    }
    data
}

// HLL dense registers are 6-bit LSB-first fields. Exactly 4 registers occupy
// 24 bits = 3 bytes, and both HLL_REGISTERS (16384 = 4096·4) and the dense
// payload (12288 = 4096·3) are exact multiples, so the codec runs in 4096
// remainder-free groups: one 24-bit word per group instead of per-register
// bit/8, bit%8, and masked-OR byte loads/stores. (frankenredis-kgsni)
fn hll_encode_dense_registers(registers: &[u8]) -> Vec<u8> {
    let mut payload = vec![0u8; HLL_REDIS_DENSE_REGISTER_BYTES];
    for (regs, bytes) in registers
        .chunks_exact(4)
        .zip(payload.chunks_exact_mut(3))
        .take(HLL_REGISTERS / 4)
    {
        let w = (u32::from(regs[0] & 0x3f))
            | (u32::from(regs[1] & 0x3f) << 6)
            | (u32::from(regs[2] & 0x3f) << 12)
            | (u32::from(regs[3] & 0x3f) << 18);
        bytes[0] = w as u8;
        bytes[1] = (w >> 8) as u8;
        bytes[2] = (w >> 16) as u8;
    }
    payload
}

fn hll_decode_dense_registers(payload: &[u8]) -> Result<Vec<u8>, StoreError> {
    if payload.len() != HLL_REDIS_DENSE_REGISTER_BYTES {
        return Err(StoreError::InvalidHllValue);
    }
    let mut registers = vec![0u8; HLL_REGISTERS];
    for (regs, bytes) in registers.chunks_exact_mut(4).zip(payload.chunks_exact(3)) {
        let w = u32::from(bytes[0]) | (u32::from(bytes[1]) << 8) | (u32::from(bytes[2]) << 16);
        regs[0] = (w & 0x3f) as u8;
        regs[1] = ((w >> 6) & 0x3f) as u8;
        regs[2] = ((w >> 12) & 0x3f) as u8;
        regs[3] = ((w >> 18) & 0x3f) as u8;
    }
    Ok(registers)
}

fn hll_encode_sparse_registers(registers: &[u8]) -> Option<Vec<u8>> {
    let opcodes = hll_sparse_opcodes(registers)?;
    let mut payload = Vec::with_capacity(opcodes.len());
    for opcode in opcodes {
        match opcode {
            HllSparseOpcode::Zero(len) => {
                if !(1..=HLL_SPARSE_ZERO_MAX_LEN).contains(&len) {
                    return None;
                }
                payload.push((len - 1) as u8);
            }
            HllSparseOpcode::XZero(len) => {
                if !(1..=HLL_SPARSE_XZERO_MAX_LEN).contains(&len) {
                    return None;
                }
                let adjusted = len - 1;
                payload.push(HLL_SPARSE_XZERO_BIT | ((adjusted >> 8) as u8 & 0x3f));
                payload.push(adjusted as u8);
            }
            HllSparseOpcode::Val { value, len } => {
                if !(1..=HLL_SPARSE_VAL_MAX_VALUE).contains(&value)
                    || !(1..=HLL_SPARSE_VAL_MAX_LEN).contains(&len)
                {
                    return None;
                }
                payload.push(HLL_SPARSE_VAL_BIT | ((value - 1) << 2) | ((len - 1) as u8));
            }
        }
    }
    Some(payload)
}

/// Which upstream sparse walk a PF command emulates when it decodes a sparse
/// HLL whose opcodes pass the structural gate but do not cleanly cover exactly
/// `HLL_REGISTERS` registers. Redis surfaces register-level corruption
/// *per command* rather than uniformly, so the same gate-valid-but-corrupt
/// value can be tolerated by one command and rejected by another.
/// (frankenredis-yiu5p)
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum HllDecode {
    /// Mirrors `hyperloglog.c::hllSparseRegHisto` (single-key `PFCOUNT`): every
    /// opcode is walked and the accumulated register index must land on exactly
    /// `HLL_REGISTERS`. There is no overflow tolerance — a `VAL` run that would
    /// push the index past the end still accumulates, so the final
    /// `idx != HLL_REGISTERS` check reports the object corrupt.
    Strict,
    /// Mirrors `hyperloglog.c::hllSparseToDense` / `hllMerge` (`PFMERGE`,
    /// multi-key `PFCOUNT`, and the `PFDEBUG GETREG/DECODE/TODENSE` debug ops):
    /// a `VAL` opcode whose run would overflow past `HLL_REGISTERS` stops the
    /// walk cleanly, so trailing `VAL` garbage after a complete register set is
    /// tolerated. `ZERO`/`XZERO` overflow is *not* tolerated (upstream advances
    /// the index unconditionally for those), so a final index other than
    /// `HLL_REGISTERS` is still rejected.
    Tolerant,
    /// Mirrors `hyperloglog.c::hllSparseSet` (`PFADD`): the add only walks far
    /// enough to reach each element's target register — always one of the first
    /// `HLL_REGISTERS` positions — so *any* trailing opcode garbage (VAL or
    /// XZERO) past a complete register set is ignored. The walk fills up to
    /// exactly `HLL_REGISTERS` and stops; an opcode stream that never covers a
    /// full register set is still rejected. (Upstream's per-element tolerance of
    /// a *truncated* prefix is target-index-and-byte dependent — undefined on
    /// corrupt input — and is not reproduced.)
    Add,
}

/// Parse just the structural header of a (potentially Redis-form) HLL string,
/// mirroring `isHLLObjectOrReply` followed by a read of `hdr->encoding` with no
/// register decode. Used by `PFDEBUG ENCODING`, which upstream reports the
/// encoding from the header alone and so tolerates a corrupt register payload.
/// (frankenredis-yiu5p)
fn hll_parse_encoding(data: &[u8]) -> Result<HllEncoding, StoreError> {
    if data.starts_with(HLL_REDIS_MAGIC) {
        let Some(&encoding) = data.get(HLL_REDIS_MAGIC.len()) else {
            return Err(StoreError::InvalidHllValue);
        };
        match encoding {
            HLL_REDIS_DENSE_ENCODING if data.len() == HLL_REDIS_DENSE_SIZE => {
                return Ok(HllEncoding::Dense);
            }
            HLL_REDIS_SPARSE_ENCODING if data.len() >= HLL_REDIS_HEADER_SIZE => {
                return Ok(HllEncoding::Sparse);
            }
            _ => {}
        }
        if data.len() == HLL_LEGACY_DATA_SIZE {
            return Ok(HllEncoding::Dense);
        }
        return Err(StoreError::InvalidHllValue);
    }
    if data.len() == HLL_DATA_SIZE && data.starts_with(HLL_MAGIC_V2) {
        return HllEncoding::from_byte(data[HLL_MAGIC_V2.len()]).ok_or(StoreError::InvalidHllValue);
    }
    Err(StoreError::InvalidHllValue)
}

fn hll_decode_sparse_registers(payload: &[u8], mode: HllDecode) -> Result<Vec<u8>, StoreError> {
    // A fixed-size register array (zero-filled) lets ZERO/XZERO runs advance the
    // index without allocating, exactly like upstream which only writes VAL
    // runs into the dense buffer; `iter_mut().skip().take()` is bounds-safe when
    // a strict-mode overflow pushes `idx` past the end (the trailing
    // `idx != HLL_REGISTERS` check then rejects the object).
    let mut registers = vec![0u8; HLL_REGISTERS];
    let mut idx: usize = 0;
    let mut p = 0;
    while p < payload.len() {
        let byte = payload[p];
        let (value, runlen, advance) = if byte & 0xc0 == 0 {
            (0u8, usize::from(byte & 0x3f) + 1, 1)
        } else if byte & 0xc0 == HLL_SPARSE_XZERO_BIT {
            let Some(&next) = payload.get(p + 1) else {
                // A dangling XZERO opcode in an otherwise gate-valid sparse HLL
                // is corruption, not a non-HLL string → INVALIDOBJ upstream.
                return Err(StoreError::CorruptedHllValue);
            };
            (
                0u8,
                (((usize::from(byte & 0x3f)) << 8) | usize::from(next)) + 1,
                2,
            )
        } else {
            (((byte >> 2) & 0x1f) + 1, usize::from(byte & 0x03) + 1, 1)
        };
        // `value == 0` ⟺ a ZERO/XZERO run (VAL values are 1..=32).
        let is_val = value != 0;
        if mode == HllDecode::Add && idx.saturating_add(runlen) >= HLL_REGISTERS {
            // PFADD (hllSparseSet) only walks to each target register, which
            // always lies in the first HLL_REGISTERS positions — so it fills the
            // remainder of the register set and ignores ALL trailing opcode
            // garbage (VAL or XZERO) past it.
            if is_val {
                for r in registers.iter_mut().skip(idx) {
                    *r = value;
                }
            }
            idx = HLL_REGISTERS;
            break;
        }
        if mode == HllDecode::Tolerant && is_val && idx + runlen > HLL_REGISTERS {
            // Upstream hllSparseToDense / hllMerge break on a VAL run that would
            // overflow, tolerating trailing VAL garbage; the strict (histogram)
            // walk instead keeps accumulating and rejects below.
            break;
        }
        if is_val {
            for r in registers.iter_mut().skip(idx).take(runlen) {
                *r = value;
            }
        }
        idx = idx.saturating_add(runlen);
        p += advance;
    }
    if idx == HLL_REGISTERS {
        Ok(registers)
    } else {
        // Opcodes that pass the gate but don't sum to HLL_REGISTERS (truncated or
        // trailing garbage) are a corrupt HLL object, not a non-HLL value.
        Err(StoreError::CorruptedHllValue)
    }
}

fn hll_sparse_opcodes(registers: &[u8]) -> Option<Vec<HllSparseOpcode>> {
    let mut opcodes = Vec::new();
    let mut index = 0;
    while index < registers.len() {
        let value = registers[index];
        let mut run_len = 1usize;
        while index + run_len < registers.len() && registers[index + run_len] == value {
            run_len += 1;
        }
        if value == 0 {
            let mut remaining = run_len;
            while remaining > 0 {
                let chunk = if remaining > HLL_SPARSE_ZERO_MAX_LEN {
                    remaining.min(HLL_SPARSE_XZERO_MAX_LEN)
                } else {
                    remaining
                };
                if chunk > HLL_SPARSE_ZERO_MAX_LEN {
                    opcodes.push(HllSparseOpcode::XZero(chunk));
                } else {
                    opcodes.push(HllSparseOpcode::Zero(chunk));
                }
                remaining -= chunk;
            }
        } else {
            if value > HLL_SPARSE_VAL_MAX_VALUE {
                return None;
            }
            let mut remaining = run_len;
            while remaining > 0 {
                let chunk = remaining.min(HLL_SPARSE_VAL_MAX_LEN);
                opcodes.push(HllSparseOpcode::Val { value, len: chunk });
                remaining -= chunk;
            }
        }
        index += run_len;
    }
    Some(opcodes)
}

fn hll_sparse_storage_len(registers: &[u8]) -> Option<usize> {
    hll_sparse_opcodes(registers).map(|opcodes| {
        HLL_REDIS_HEADER_SIZE
            + opcodes
                .iter()
                .map(|opcode| match opcode {
                    HllSparseOpcode::Zero(_) | HllSparseOpcode::Val { .. } => 1,
                    HllSparseOpcode::XZero(_) => 2,
                })
                .sum::<usize>()
    })
}

fn hll_sparse_should_promote(registers: &[u8], max_sparse_bytes: usize) -> bool {
    match hll_sparse_storage_len(registers) {
        Some(len) => len > max_sparse_bytes,
        None => true,
    }
}

fn hll_sparse_decode(registers: &[u8]) -> Result<String, StoreError> {
    let mut segments = Vec::new();
    for opcode in hll_sparse_opcodes(registers).ok_or(StoreError::InvalidHllValue)? {
        match opcode {
            HllSparseOpcode::Zero(len) => segments.push(format!("z:{len}")),
            HllSparseOpcode::XZero(len) => segments.push(format!("Z:{len}")),
            HllSparseOpcode::Val { value, len } => segments.push(format!("v:{value},{len}")),
        }
    }
    Ok(segments.join(" "))
}

/// `hllSigma` from redis hyperloglog.c — converges via exact f64 equality, so
/// it reproduces upstream's loop bit-for-bit. (frankenredis-2bpzv)
fn hll_sigma(mut x: f64) -> f64 {
    if x == 1.0 {
        return f64::INFINITY;
    }
    let mut y = 1.0_f64;
    let mut z = x;
    loop {
        x *= x;
        let z_prime = z;
        z += x * y;
        y += y;
        if z_prime == z {
            break;
        }
    }
    z
}

/// `hllTau` from redis hyperloglog.c. (frankenredis-2bpzv)
fn hll_tau(mut x: f64) -> f64 {
    if x == 0.0 || x == 1.0 {
        return 0.0;
    }
    let mut y = 1.0_f64;
    let mut z = 1.0 - x;
    loop {
        x = x.sqrt();
        let z_prime = z;
        y *= 0.5;
        z -= (1.0 - x).powi(2) * y;
        if z_prime == z {
            break;
        }
    }
    z / 3.0
}

/// Estimate HLL cardinality using the Otmar Ertl 2017 algorithm
/// ("New cardinality estimation algorithms for HyperLogLog sketches",
/// arXiv:1702.01284), a direct port of redis 7.2.4 hyperloglog.c::hllCount.
/// The older Flajolet 2007 estimator (alpha*m^2/sum + linear-counting) that
/// fr used previously diverged from upstream by ~1 at higher cardinalities
/// even with byte-identical registers. (frankenredis-2bpzv)
fn hll_estimate(registers: &[u8]) -> u64 {
    let m = HLL_REGISTERS as f64;
    // Register-value histogram. Register rho values are 6-bit (0..=63); mask
    // keeps the index in bounds for any malformed RESTORE payload, matching
    // upstream's fixed reghisto[64].
    let mut reghisto = [0_i64; 64];
    for &reg in registers {
        reghisto[(reg as usize) & 63] += 1;
    }

    let mut z = m * hll_tau((m - reghisto[HLL_Q + 1] as f64) / m);
    for j in (1..=HLL_Q).rev() {
        z += reghisto[j] as f64;
        z *= 0.5;
    }
    z += m * hll_sigma(reghisto[0] as f64 / m);
    let e = (HLL_ALPHA_INF * m * m / z).round();
    e as u64
}

fn hll_add_to_registers(registers: &mut [u8], element: &[u8]) {
    let hash = hll_hash(element);
    let index = (hash as usize) & (HLL_REGISTERS - 1);
    let w = hash >> HLL_P;
    let count = hll_rho(w);
    if count > registers[index] {
        registers[index] = count;
    }
}

fn hll_run_selftest() -> Result<(), String> {
    const HLL_TEST_CYCLES: usize = 64;

    let mut state = 0x9e37_79b9_7f4a_7c15_u64;
    let mut next_u64 = || {
        state = state
            .wrapping_mul(6_364_136_223_846_793_005)
            .wrapping_add(1_442_695_040_888_963_407);
        state
    };

    for _ in 0..HLL_TEST_CYCLES {
        let mut expected = vec![0u8; HLL_REGISTERS];
        for value in &mut expected {
            *value = (next_u64() & 63) as u8;
        }
        let encoded = hll_encode(&expected, HllEncoding::Sparse);
        let decoded = hll_parse_registers(&encoded, HllDecode::Strict)
            .map_err(|_| "TESTFAILED encoded register payload did not round-trip".to_string())?;
        if decoded != expected {
            return Err("TESTFAILED register round-trip mismatch".to_string());
        }
    }

    let mut registers = vec![0u8; HLL_REGISTERS];
    let relerr = 1.04 / (HLL_REGISTERS as f64).sqrt();
    let mut checkpoint = 1_u64;
    let mut element = 0_u64;

    while checkpoint <= 1_000_000 {
        while element < checkpoint {
            element += 1;
            hll_add_to_registers(&mut registers, &element.to_le_bytes());
        }
        let estimate = hll_estimate(&registers);
        let abserr = estimate.abs_diff(checkpoint);
        let mut maxerr = (relerr * 6.0 * checkpoint as f64).ceil() as u64;
        if checkpoint == 10 {
            maxerr = 1;
        }
        if abserr > maxerr {
            return Err(format!(
                "TESTFAILED Too big error. card:{checkpoint} abserr:{abserr}"
            ));
        }
        checkpoint *= 10;
    }

    Ok(())
}

/// Redis-compatible glob pattern matching.
///
/// Supports `*` (match any sequence), `?` (match one byte),
/// `[abc]` (character class), `[^abc]` (negated class),
/// and `\x` (escape).
/// String-based glob match wrapper for function library filtering.
fn glob_match_str(pattern: &str, string: &str) -> bool {
    glob_match(pattern.as_bytes(), string.as_bytes())
}

/// Extract a function name from a redis.register_function call.
/// Handles patterns like:
///   redis.register_function('myFunc', function(keys, args) ...)
///   redis.register_function{function_name='myFunc', ...}
/// Pull `(name, description)` out of a `redis.register_function`
/// call. Upstream function_lua.c accepts the `description` field
/// in the table-form invocation (`{function_name='n',
/// description='d', callback=fn}`); previously we extracted only
/// the function name and dropped the description, leaving the
/// FUNCTION LIST `description` slot at nil even when the script
/// explicitly set it. (br-frankenredis-r85v)
fn extract_function_metadata(line: &str) -> Option<(String, Option<String>)> {
    // Pattern 1: redis.register_function('name', callback)
    if let Some(start) = line.find("register_function") {
        let rest = &line[start..];
        if let Some(paren) = rest.find('(') {
            let after = &rest[paren + 1..].trim_start();
            if let Some(name) = extract_quoted_string(after) {
                return Some((name, None));
            }
        }
        // Pattern 2: register_function{function_name='name',
        //              description='d', callback=fn, ...}
        if let Some(brace) = rest.find('{') {
            let after = &rest[brace + 1..];
            // Match key tokens with the `=` attached so that a
            // function_name VALUE containing the substring
            // `description` (e.g. function_name='describe_user')
            // doesn't bleed into the description slot. Tolerate
            // optional whitespace around `=`. (br-frankenredis-r85v)
            let name = extract_table_field(after, "function_name");
            let description = extract_table_field(after, "description");
            if let Some(name) = name {
                return Some((name, description));
            }
        }
    }
    None
}

/// Find `<key> *= *<quoted-string>` in a Lua-table-form argument
/// list and return the quoted value. Skips field assignments where
/// the key matches `<key>` only as a substring of another
/// identifier (e.g. `function_name` contains `description` only as
/// a value-side substring, never as a key). (br-frankenredis-r85v)
fn extract_table_field(buf: &str, key: &str) -> Option<String> {
    let bytes = buf.as_bytes();
    let key_bytes = key.as_bytes();
    let mut i = 0;
    while i + key_bytes.len() <= bytes.len() {
        if &bytes[i..i + key_bytes.len()] == key_bytes {
            // Boundary check on the LEFT — previous byte must not
            // be an ident char (letter/digit/underscore).
            let left_ok =
                i == 0 || !matches!(bytes[i - 1], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_');
            // Boundary check on the RIGHT — first non-whitespace
            // byte after key must be `=`.
            let mut j = i + key_bytes.len();
            while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                j += 1;
            }
            if left_ok && j < bytes.len() && bytes[j] == b'=' {
                let value_start = j + 1;
                let after_eq = buf[value_start..].trim_start();
                if let Some(v) = extract_quoted_string(after_eq) {
                    return Some(v);
                }
            }
        }
        i += 1;
    }
    None
}

/// Walk past a `function(params) body end` expression that begins
/// at the start of `s` and return true if the FIRST character
/// after the function expression (skipping whitespace) is a
/// comma — indicating a third positional argument to the
/// enclosing register_function call. (frankenredis-fnpos3)
fn positional_call_has_extra_arg_after_function(s: &str) -> bool {
    let bytes = s.as_bytes();
    if !s.starts_with("function") {
        return false;
    }
    let mut i = "function".len();
    // Skip the (params) header: a balanced paren expression.
    while i < bytes.len() && bytes[i].is_ascii_whitespace() {
        i += 1;
    }
    if i >= bytes.len() || bytes[i] != b'(' {
        return false;
    }
    let mut pdepth: i32 = 1;
    i += 1;
    while i < bytes.len() && pdepth > 0 {
        match bytes[i] {
            b'(' => pdepth += 1,
            b')' => pdepth -= 1,
            b'\'' | b'"' => {
                let q = bytes[i];
                i += 1;
                while i < bytes.len() && bytes[i] != q {
                    if bytes[i] == b'\\' && i + 1 < bytes.len() {
                        i += 1;
                    }
                    i += 1;
                }
            }
            _ => {}
        }
        i += 1;
    }
    // Walk the function body, matching `function`/`if`/`while`/
    // `for`/`do` openers against `end` closers.
    let mut bdepth: i32 = 1;
    while i < bytes.len() && bdepth > 0 {
        let b = bytes[i];
        if b == b'\'' || b == b'"' {
            let q = b;
            i += 1;
            while i < bytes.len() && bytes[i] != q {
                if bytes[i] == b'\\' && i + 1 < bytes.len() {
                    i += 1;
                }
                i += 1;
            }
            if i < bytes.len() {
                i += 1;
            }
            continue;
        }
        let lok = i == 0 || !matches!(bytes[i - 1], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_');
        if lok && matches!(b, b'A'..=b'Z' | b'a'..=b'z' | b'_') {
            let st = i;
            while i < bytes.len()
                && matches!(bytes[i], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_')
            {
                i += 1;
            }
            let id = &s[st..i];
            match id {
                "function" | "if" | "while" | "for" | "do" => bdepth += 1,
                "end" => bdepth -= 1,
                _ => {}
            }
            continue;
        }
        i += 1;
    }
    while i < bytes.len() && bytes[i].is_ascii_whitespace() {
        i += 1;
    }
    i < bytes.len() && bytes[i] == b','
}

/// Return the raw text after `<key>=` at top-level of a Lua
/// table body, stopping at the matching brace, paren, or comma
/// at the same depth. Used to inspect non-quoted-string values
/// like `flags={'no-writes'}` where extract_table_field is
/// limited to quoted scalars. (frankenredis-fnflags)
fn extract_table_value_raw<'a>(buf: &'a str, key: &str) -> Option<&'a str> {
    let bytes = buf.as_bytes();
    let key_bytes = key.as_bytes();
    let mut i = 0;
    while i + key_bytes.len() <= bytes.len() {
        if &bytes[i..i + key_bytes.len()] == key_bytes {
            let left_ok =
                i == 0 || !matches!(bytes[i - 1], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_');
            let mut j = i + key_bytes.len();
            while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                j += 1;
            }
            if left_ok && j < bytes.len() && bytes[j] == b'=' {
                return Some(&buf[j + 1..]);
            }
        }
        i += 1;
    }
    None
}

/// Extract the quoted string entries from a Lua flags table value
/// like `{'no-writes', 'allow-oom'}`. Returns the entries in
/// source order, ignoring whitespace and commas. (frankenredis-fnflags)
fn extract_flag_strings(value: &str) -> Vec<String> {
    let bytes = value.as_bytes();
    let mut out = Vec::new();
    let Some(start) = bytes.iter().position(|&b| b == b'{') else {
        return out;
    };
    let mut i = start + 1;
    let mut depth: i32 = 1;
    while i < bytes.len() && depth > 0 {
        let b = bytes[i];
        if b == b'{' {
            depth += 1;
            i += 1;
            continue;
        }
        if b == b'}' {
            depth -= 1;
            i += 1;
            continue;
        }
        if b == b'\'' || b == b'"' {
            let quote = b;
            let s = i + 1;
            i += 1;
            while i < bytes.len() && bytes[i] != quote {
                if bytes[i] == b'\\' && i + 1 < bytes.len() {
                    i += 1;
                }
                i += 1;
            }
            if depth == 1 {
                out.push(value[s..i].to_string());
            }
            if i < bytes.len() {
                i += 1;
            }
            continue;
        }
        i += 1;
    }
    out
}

/// Walk a Lua table-form body and return the first `<ident>=`
/// token at top-level whose ident is not in `allowed`. Skips
/// identifiers inside quoted strings, nested braces, and inside
/// `function ... end` blocks (the common case for `callback=fn`).
/// Best-effort: complex nested control-flow inside callback
/// bodies may end the scan early, which only produces false
/// negatives (no error reported) — never false positives.
/// (frankenredis-fnukn)
fn find_unknown_table_key(buf: &str, allowed: &[&str]) -> Option<String> {
    let bytes = buf.as_bytes();
    let mut i = 0;
    let mut brace_depth: i32 = 0;
    while i < bytes.len() {
        let b = bytes[i];
        // Skip over single- or double-quoted strings.
        if b == b'\'' || b == b'"' {
            let quote = b;
            i += 1;
            while i < bytes.len() && bytes[i] != quote {
                if bytes[i] == b'\\' && i + 1 < bytes.len() {
                    i += 1;
                }
                i += 1;
            }
            if i < bytes.len() {
                i += 1;
            }
            continue;
        }
        if b == b'{' {
            brace_depth += 1;
            i += 1;
            continue;
        }
        if b == b'}' {
            if brace_depth == 0 {
                break;
            }
            brace_depth -= 1;
            i += 1;
            continue;
        }
        let left_ok =
            i == 0 || !matches!(bytes[i - 1], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_');
        if left_ok && matches!(b, b'A'..=b'Z' | b'a'..=b'z' | b'_') {
            let start = i;
            while i < bytes.len()
                && matches!(bytes[i], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_')
            {
                i += 1;
            }
            let ident_end = i;
            let ident = &buf[start..ident_end];
            // When entering a `function ... end` expression at the
            // top of the table, skip past the matching `end` token.
            // Use a coarse keyword-block depth counter that treats
            // `function`/`if`/`while`/`for`/`do` as openers and
            // `end` as a closer. Imperfect for nested control flow
            // but sufficient for typical Redis function bodies.
            if brace_depth == 0 && ident == "function" {
                let mut depth: i32 = 1;
                while depth > 0 && i < bytes.len() {
                    let c = bytes[i];
                    if c == b'\'' || c == b'"' {
                        let q = c;
                        i += 1;
                        while i < bytes.len() && bytes[i] != q {
                            if bytes[i] == b'\\' && i + 1 < bytes.len() {
                                i += 1;
                            }
                            i += 1;
                        }
                        if i < bytes.len() {
                            i += 1;
                        }
                        continue;
                    }
                    let lok = i == 0
                        || !matches!(
                            bytes[i - 1],
                            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_'
                        );
                    if lok && matches!(c, b'A'..=b'Z' | b'a'..=b'z' | b'_') {
                        let s = i;
                        while i < bytes.len()
                            && matches!(
                                bytes[i],
                                b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_'
                            )
                        {
                            i += 1;
                        }
                        let id = &buf[s..i];
                        match id {
                            "function" | "if" | "while" | "for" | "do" => depth += 1,
                            "end" => depth -= 1,
                            _ => {}
                        }
                        continue;
                    }
                    i += 1;
                }
                continue;
            }
            if brace_depth == 0 {
                let mut j = i;
                while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                    j += 1;
                }
                if j < bytes.len()
                    && bytes[j] == b'='
                    && bytes.get(j + 1).copied() != Some(b'=')
                    && !allowed.contains(&ident)
                {
                    return Some(ident.to_string());
                }
            }
            continue;
        }
        i += 1;
    }
    None
}

/// Return true if `<key> *= *...` appears in `buf` with the same
/// left-boundary discipline as `extract_table_field`, regardless
/// of the value shape. Used to detect presence of fields whose
/// values are not quoted strings (e.g. `callback=function() ...`)
/// so we can mirror upstream's required-field wording without
/// fully parsing Lua. (frankenredis-fncb)
fn has_table_key(buf: &str, key: &str) -> bool {
    let bytes = buf.as_bytes();
    let key_bytes = key.as_bytes();
    let mut i = 0;
    while i + key_bytes.len() <= bytes.len() {
        if &bytes[i..i + key_bytes.len()] == key_bytes {
            let left_ok =
                i == 0 || !matches!(bytes[i - 1], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_');
            let mut j = i + key_bytes.len();
            while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                j += 1;
            }
            if left_ok && j < bytes.len() && bytes[j] == b'=' {
                return true;
            }
        }
        i += 1;
    }
    false
}

fn extract_quoted_string(s: &str) -> Option<String> {
    let s = s.trim();
    let quote = s.as_bytes().first().copied()?;
    if quote != b'\'' && quote != b'"' {
        return None;
    }
    let rest = &s[1..];
    let end = rest.find(quote as char)?;
    Some(rest[..end].to_string())
}

/// (frankenredis-2wgom) The longest LITERAL prefix every string matching glob
/// `pattern` must start with: the bytes before the first unescaped glob
/// metacharacter (`*`, `?`, `[`) or escape (`\`). Stopping at `\` *under*-
/// approximates the true prefix (a shorter prefix widens the candidate range),
/// which is always safe because the per-candidate `glob_match` still filters
/// exactly. Empty when the pattern opens with a metacharacter — no pruning.
fn glob_literal_prefix(pattern: &[u8]) -> &[u8] {
    let mut i = 0;
    while i < pattern.len() {
        match pattern[i] {
            b'*' | b'?' | b'[' | b'\\' => break,
            _ => i += 1,
        }
    }
    &pattern[..i]
}

/// (frankenredis-2wgom) Exclusive upper bound for the `BTreeSet` range that
/// selects exactly the keys having `prefix` as a prefix: increment the last byte
/// below `0xFF`, dropping trailing `0xFF`s. `None` means an all-`0xFF` (or empty)
/// prefix, i.e. the range is unbounded above (`prefix..`).
fn prefix_range_end(prefix: &[u8]) -> Option<Vec<u8>> {
    let mut end = prefix.to_vec();
    while let Some(last) = end.last_mut() {
        if *last < 0xFF {
            *last += 1;
            return Some(end);
        }
        end.pop();
    }
    None
}

pub fn glob_match(pattern: &[u8], string: &[u8]) -> bool {
    glob_match_inner(pattern, string, 0, 0)
}

fn glob_match_inner(pattern: &[u8], string: &[u8], mut pi: usize, mut si: usize) -> bool {
    let mut star_pi = usize::MAX;
    let mut star_si = usize::MAX;

    while si < string.len() {
        if pi < pattern.len() && pattern[pi] == b'\\' && pi + 1 < pattern.len() {
            // Escaped character: must match literally.
            if string[si] == pattern[pi + 1] {
                pi += 2;
                si += 1;
                continue;
            }
        } else if pi < pattern.len() && pattern[pi] == b'*' {
            star_pi = pi;
            star_si = si;
            pi += 1;
            continue;
        } else if pi < pattern.len() && pattern[pi] == b'?' {
            pi += 1;
            si += 1;
            continue;
        } else if pi < pattern.len() && pattern[pi] == b'[' {
            if let Some((matched, end)) = match_character_class(pattern, pi, string[si])
                && matched
            {
                pi = end;
                si += 1;
                continue;
            }
        } else if pi < pattern.len() && pattern[pi] == string[si] {
            pi += 1;
            si += 1;
            continue;
        }

        // Backtrack to last star.
        if star_pi != usize::MAX {
            pi = star_pi + 1;
            star_si += 1;
            si = star_si;
            continue;
        }

        return false;
    }

    // Consume trailing stars.
    while pi < pattern.len() && pattern[pi] == b'*' {
        pi += 1;
    }
    pi == pattern.len()
}

/// Match a `[...]` character class at `pattern[pi]`.
/// Returns `Some((matched, index_after_bracket))` or `None` if malformed.
fn match_character_class(pattern: &[u8], pi: usize, ch: u8) -> Option<(bool, usize)> {
    debug_assert_eq!(pattern[pi], b'[');
    let mut i = pi + 1;
    let negate = i < pattern.len() && pattern[i] == b'^';
    if negate {
        i += 1;
    }

    let mut matched = false;
    loop {
        if i + 1 < pattern.len() && pattern[i] == b'\\' {
            i += 1;
            if pattern[i] == ch {
                matched = true;
            }
            i += 1;
            continue;
        }

        if i >= pattern.len() {
            // Redis malformed-class behavior: treat the final class byte as the terminator.
            if i > pi + 1 {
                i -= 1;
            }
            break;
        }

        if pattern[i] == b']' {
            break;
        }

        if i + 2 < pattern.len() && pattern[i + 1] == b'-' {
            let mut lo = pattern[i];
            let mut hi = pattern[i + 2];
            if lo > hi {
                std::mem::swap(&mut lo, &mut hi);
            }
            if ch >= lo && ch <= hi {
                matched = true;
            }
            i += 3;
            continue;
        }

        if pattern[i] == ch {
            matched = true;
        }
        i += 1;
    }

    let result = if negate { !matched } else { matched };
    Some((result, (i + 1).min(pattern.len())))
}

