    fn group_read_options(
        cursor: StreamGroupReadCursor,
        noack: bool,
        count: Option<usize>,
    ) -> StreamGroupReadOptions {
        StreamGroupReadOptions {
            cursor,
            noack,
            count,
        }
    }

    fn function_library_snapshot(store: &Store) -> Vec<(String, String, Vec<u8>, Vec<String>)> {
        store
            .function_list(None)
            .into_iter()
            .map(|library| {
                let mut function_names: Vec<String> = library
                    .functions
                    .iter()
                    .map(|function| function.name.clone())
                    .collect();
                function_names.sort();
                (
                    library.name.clone(),
                    library.engine.clone(),
                    library.code.clone(),
                    function_names,
                )
            })
            .collect()
    }

    fn sample_function_library(name: &str, first_fn: &str, second_fn: &str) -> Vec<u8> {
        format!(
            "#!lua name={name}\n\
             redis.register_function('{first_fn}', function(keys, args) return #keys + #args end)\n\
             redis.register_function{{function_name='{second_fn}', callback=function(keys, args) return 0 end}}\n"
        )
        .into_bytes()
    }

    fn sample_function_library_from_seed(seed: u16) -> Vec<u8> {
        sample_function_library(
            &format!("seedlib_{seed:04x}"),
            &format!("alpha_{seed:04x}"),
            &format!("beta_{seed:04x}"),
        )
    }

    fn sample_replacement_function_library_from_seed(seed: u16) -> Vec<u8> {
        sample_function_library(
            &format!("seedlib_{seed:04x}"),
            &format!("gamma_{seed:04x}"),
            &format!("delta_{seed:04x}"),
        )
    }

    #[test]
    fn set_get_and_del() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 100);
        assert_eq!(store.get(b"k", 100).unwrap(), Some(b"v".to_vec()));
        assert_eq!(store.del(&[b"k".to_vec()], 100), 1);
        assert_eq!(store.get(b"k", 100).unwrap(), None);
    }

    #[test]
    fn sentinel_probe_result_marks_then_clears_s_down_and_o_down() {
        // (frankenredis-pkdgs) A monitored master unreachable longer than
        // down-after-milliseconds must transition to S_DOWN — and, with quorum=1,
        // the sentinel's own vote meets quorum so it also becomes O_DOWN — both
        // clearing on the next successful probe. Driven by the monitoring tick.
        let mut store = Store::new();
        store
            .sentinel_state
            .monitor("mymaster", "127.0.0.1", 6379, 1)
            .unwrap();
        store
            .sentinel_state
            .masters
            .get_mut("mymaster")
            .unwrap()
            .down_after_period = 100;

        // First failed probe arms the disconnect; not yet down.
        store.apply_sentinel_probe_result("mymaster", 1000, None);
        assert!(!store.sentinel_state.masters["mymaster"].is_s_down());
        assert!(!store.sentinel_state.masters["mymaster"].is_o_down());
        // A second failure past down-after-period flips S_DOWN, and with quorum=1
        // the self-vote flips O_DOWN too.
        store.apply_sentinel_probe_result("mymaster", 1500, None);
        assert!(
            store.sentinel_state.masters["mymaster"].is_s_down(),
            "master should be S_DOWN after down-after-period elapsed while unreachable"
        );
        assert!(
            store.sentinel_state.masters["mymaster"].is_o_down(),
            "quorum=1: the self S_DOWN vote alone must flip O_DOWN"
        );
        // A successful PING+INFO probe clears both.
        let info = "# Server\r\nrun_id:abc\r\n# Replication\r\nrole:master\r\n";
        store.apply_sentinel_probe_result("mymaster", 1600, Some(info));
        assert!(
            !store.sentinel_state.masters["mymaster"].is_s_down(),
            "S_DOWN must clear once the master answers again"
        );
        assert!(
            !store.sentinel_state.masters["mymaster"].is_o_down(),
            "O_DOWN must clear once the master answers again"
        );
    }

    #[test]
    fn keyspace_hit_and_miss_counters_follow_store_lookup_paths() {
        let mut store = Store::new();
        store.set(b"s".to_vec(), b"v".to_vec(), None, 0);
        store
            .hset(b"h", b"field".to_vec(), b"value".to_vec(), 0)
            .expect("hset");
        store.rpush(b"list", &[b"item".to_vec()], 0).expect("rpush");
        store.sadd(b"set", &[b"member".to_vec()], 0).expect("sadd");
        store
            .zadd(b"zset", &[(1.0, b"member".to_vec())], 0)
            .expect("zadd");
        store
            .xadd(b"stream", (1, 0), &[(b"f".to_vec(), b"v".to_vec())], 0)
            .expect("xadd");

        assert_eq!(store.get(b"s", 0).unwrap(), Some(b"v".to_vec()));
        assert!(store.exists(b"s", 0));
        assert_eq!(store.get(b"missing", 0).expect("missing string read"), None);
        assert_eq!(
            store.hget(b"h", b"field", 0).expect("existing hash field"),
            Some(b"value".to_vec())
        );
        assert_eq!(
            store.lindex(b"list", 0, 0).expect("list lookup"),
            Some(b"item".to_vec())
        );
        assert!(store.sismember(b"set", b"member", 0).expect("set lookup"));
        assert_eq!(
            store.zscore(b"zset", b"member", 0).expect("zset lookup"),
            Some(1.0)
        );
        assert_eq!(store.xlen(b"stream", 0).expect("stream lookup"), 1);
        assert_eq!(
            store
                .smembers(b"missing-set", 0)
                .expect("missing set lookup"),
            Vec::<Vec<u8>>::new()
        );
        assert_eq!(store.xlen(b"missing-stream", 0).expect("missing stream"), 0);

        assert_eq!(store.stat_keyspace_hits, 7);
        assert_eq!(store.stat_keyspace_misses, 3);
    }

    #[test]
    fn write_spop_does_not_count_keyspace_lookup_but_read_dump_does() {
        // (frankenredis-934ax) Upstream only bumps keyspace_hits/misses in
        // lookupKeyRead*; write commands (lookupKeyWrite*) must not. SPOP is a
        // write → no count; DUMP is a read → counts hit on present / miss on
        // absent. Verified vs redis 7.2.4.
        let mut store = Store::new();
        store
            .sadd(b"s", &[b"a".to_vec(), b"b".to_vec()], 0)
            .unwrap();
        store.stat_keyspace_hits = 0;
        store.stat_keyspace_misses = 0;

        store.spop(b"s", 0).unwrap(); // write: no count
        assert_eq!(store.stat_keyspace_hits, 0, "SPOP must not bump hits");
        assert_eq!(store.stat_keyspace_misses, 0, "SPOP must not bump misses");
        store.spop(b"missing", 0).unwrap(); // write on missing: still no count
        assert_eq!(store.stat_keyspace_hits, 0);
        assert_eq!(store.stat_keyspace_misses, 0);

        store.set(b"d".to_vec(), b"v".to_vec(), None, 0);
        store.dump_key(b"d", 0); // read on present: +1 hit
        assert_eq!(store.stat_keyspace_hits, 1, "DUMP present must bump a hit");
        assert_eq!(store.stat_keyspace_misses, 0);
        store.dump_key(b"nope", 0); // read on absent: +1 miss
        assert_eq!(store.stat_keyspace_hits, 1);
        assert_eq!(
            store.stat_keyspace_misses, 1,
            "DUMP absent must bump a miss"
        );
    }

    #[test]
    fn memory_usage_small_encoding_baselines_match_vendored_redis() {
        let mut store = Store::new();

        store.set(b"sk".to_vec(), b"hello".to_vec(), None, 0);
        assert_eq!(store.memory_usage_for_key(b"sk", 0), Some(64));

        store.lpush(b"el", &[Vec::new()], 0).expect("lpush empty");
        assert_eq!(store.memory_usage_for_key(b"el", 0), Some(64));

        store
            .lpush(
                b"lp",
                &[
                    b"a".to_vec(),
                    b"b".to_vec(),
                    b"c".to_vec(),
                    b"d".to_vec(),
                    b"e".to_vec(),
                ],
                0,
            )
            .expect("lpush listpack");
        assert_eq!(store.memory_usage_for_key(b"lp", 0), Some(72));

        assert!(
            store
                .hset(b"hk", b"f1".to_vec(), b"v1".to_vec(), 0)
                .expect("hset f1")
        );
        assert!(
            store
                .hset(b"hk", b"f2".to_vec(), b"v2".to_vec(), 0)
                .expect("hset f2")
        );
        assert_eq!(store.memory_usage_for_key(b"hk", 0), Some(72));

        store
            .zadd(
                b"zk",
                &[
                    (1.0, b"a".to_vec()),
                    (2.0, b"b".to_vec()),
                    (3.0, b"c".to_vec()),
                ],
                0,
            )
            .expect("zadd listpack");
        assert_eq!(store.memory_usage_for_key(b"zk", 0), Some(72));

        store
            .xadd(b"xs", (1, 0), &[(b"f".to_vec(), b"v".to_vec())], 0)
            .expect("xadd stream");
        // (frankenredis-4h50d) Vendored returns 4728 for a stream
        // with a single tiny entry. fr now matches: base 656 + first
        // listpack node 4072 = 4728.
        assert_eq!(store.memory_usage_for_key(b"xs", 0), Some(4_728));
    }

