    #[test]
    fn get_string_bytes_matches_get_stats_and_touch() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 100);
        store.reset_info_stats();

        let copied = store
            .get_string_bytes(b"k", 200)
            .map(|value| value.map(std::borrow::Cow::into_owned))
            .expect("borrowed get succeeds");
        assert_eq!(copied, Some(b"v".to_vec()));
        assert_eq!(store.stat_keyspace_hits, 1);
        assert_eq!(store.stat_keyspace_misses, 0);
        assert_eq!(
            store
                .entries
                .get(b"k".as_ref())
                .expect("entry remains")
                .last_access_ms,
            200
        );

        let missing = store
            .get_string_bytes(b"missing", 300)
            .map(|value| value.map(std::borrow::Cow::into_owned))
            .expect("missing borrowed get succeeds");
        assert_eq!(missing, None);
        assert_eq!(store.stat_keyspace_misses, 1);

        store
            .rpush(b"list", &[b"x".to_vec()], 400)
            .expect("create list");
        store.reset_info_stats();
        let wrong_type = store.get_string_bytes(b"list", 500);
        assert!(matches!(wrong_type, Err(StoreError::WrongType)));
        assert_eq!(store.stat_keyspace_hits, 1);
        assert_eq!(
            store
                .entries
                .get(b"list".as_ref())
                .expect("list entry remains")
                .last_access_ms,
            400
        );
    }

    #[test]
    fn touch_and_sort_update_lru_and_keyspace_stats() {
        let mut store = Store::new();
        store
            .rpush(b"list", &[b"item".to_vec()], 10)
            .expect("rpush");
        store.sadd(b"set", &[b"member".to_vec()], 10).expect("sadd");
        store.reset_info_stats();

        assert_eq!(
            store
                .entries
                .get(b"list".as_ref())
                .expect("list entry")
                .last_access_ms,
            10
        );
        assert_eq!(
            store
                .entries
                .get(b"set".as_ref())
                .expect("set entry")
                .last_access_ms,
            10
        );

        let touched = store.touch(&[b"list", b"missing"], 100);
        assert_eq!(touched, 1);
        assert_eq!(
            store
                .entries
                .get(b"list".as_ref())
                .expect("list entry")
                .last_access_ms,
            100
        );
        assert_eq!(store.stat_keyspace_hits, 1);
        assert_eq!(store.stat_keyspace_misses, 1);

        let elements = store.sort_elements(b"set", 200).expect("sort elements");
        assert_eq!(elements, vec![b"member".to_vec()]);
        assert_eq!(
            store
                .entries
                .get(b"set".as_ref())
                .expect("set entry")
                .last_access_ms,
            200
        );
        assert_eq!(store.stat_keyspace_hits, 2);
        assert_eq!(store.stat_keyspace_misses, 1);
    }

    #[test]
    fn sort_destructively_converts_listpack_zset_to_skiplist() {
        // Upstream sort.c::sortCommand converts a sorted set to skiplist before
        // sorting (unconditionally, incl. SORT_RO). A small listpack zset must
        // therefore report `skiplist` after any SORT read. Sets are unaffected.
        let mut store = Store::new();
        let _ = store.zadd(b"z", &[(1.0, b"a".to_vec()), (2.0, b"bb".to_vec())], 0);
        assert_eq!(store.object_encoding(b"z", 0), Some("listpack"));
        let _ = store.sort_elements(b"z", 0).expect("sort elements");
        assert_eq!(
            store.object_encoding(b"z", 0),
            Some("skiplist"),
            "SORT must destructively promote a listpack zset to skiplist"
        );
        // A set is NOT converted by SORT.
        let _ = store.sadd(b"s", &[b"a".to_vec(), b"bb".to_vec()], 0);
        let enc_before = store.object_encoding(b"s", 0);
        let _ = store.sort_elements(b"s", 0).expect("sort set");
        assert_eq!(store.object_encoding(b"s", 0), enc_before, "SORT must not convert a set");
    }

    #[test]
    fn latency_tracker_records_latest_history_and_reset() {
        let mut store = Store::new();

        store.record_latency_sample("command", 5, 10);
        store.record_latency_sample("command", 8, 12);
        store.record_latency_sample("fast-command", 2, 11);

        assert_eq!(
            store.latency_latest(),
            vec![
                (
                    "command".to_string(),
                    LatencySample {
                        timestamp_sec: 12,
                        duration_ms: 8,
                    },
                ),
                (
                    "fast-command".to_string(),
                    LatencySample {
                        timestamp_sec: 11,
                        duration_ms: 2,
                    },
                ),
            ]
        );
        assert_eq!(
            store.latency_history("command"),
            vec![
                LatencySample {
                    timestamp_sec: 10,
                    duration_ms: 5,
                },
                LatencySample {
                    timestamp_sec: 12,
                    duration_ms: 8,
                },
            ]
        );
        assert_eq!(store.latency_reset(&["command"]), 1);
        assert!(store.latency_history("command").is_empty());
        assert_eq!(store.latency_reset(&[]), 1);
        assert!(store.latency_latest().is_empty());
    }

