        store.notify_keyspace_events = NOTIFY_KEYEVENT | NOTIFY_GENERIC;
        store.set(b"k".to_vec(), b"v".to_vec(), None, 1_000);

        assert!(store.expire_at_milliseconds(b"k", 5_000, 1_000));
