    #[test]
    fn maxmemory_samples_limits_lru_candidate_pool() {
        let mut store = Store::new();
        store.maxmemory_policy = MaxmemoryPolicy::AllkeysLru;
        for idx in 0..8 {
            let key = format!("sample:{idx}");
            store.set(key.into_bytes(), b"v".to_vec(), None, idx);
        }

        let oldest = b"sample:0".to_vec();
        let mut probe_seed = 1;
        let (chosen_seed, sampled_key) = loop {
            assert!(
                probe_seed < 4096,
                "expected to find an LCG seed that samples a non-oldest key"
            );
            store.rng_seed = probe_seed;
            let sampled = store.sampled_eviction_candidate_keys(false, 1);
            let sampled_key = sampled.first().expect("non-empty sample").clone();
            if sampled_key != oldest {
                break (probe_seed, sampled_key);
            }
            probe_seed += 1;
        };

        store.rng_seed = chosen_seed;
        assert_eq!(
            store.select_eviction_candidate(10_000, 1),
            Some(sampled_key)
        );
        assert_eq!(store.select_eviction_candidate(10_000, 32), Some(oldest));
    }

    #[test]
    fn state_digest_changes_on_mutation() {
        let mut store = Store::new();
        let digest_a = store.state_digest();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 0);
        let digest_b = store.state_digest();
        assert_ne!(digest_a, digest_b);
        store.del(&[b"k".to_vec()], 0);
        let digest_c = store.state_digest();
        assert_ne!(digest_b, digest_c);
    }

    #[test]
    fn state_digest_matches_full_scan_after_direct_mutation_paths() {
        fn assert_digest_matches(store: &mut Store) {
            let expected = format!("{:016x}", store.state_digest_full_scan());
            assert_eq!(store.state_digest(), expected);
        }

        let mut store = Store::new();

        store.set(b"ttl".to_vec(), b"value".to_vec(), None, 0);
        store
            .getex(b"ttl", Some(Some(5_000)), 100)
            .expect("getex should set expiry");
        assert_digest_matches(&mut store);

        store
            .hset(b"hash", b"field".to_vec(), b"value".to_vec(), 0)
            .expect("hset should create hash");
        store
            .hset(b"hash", b"field".to_vec(), b"updated".to_vec(), 1)
            .expect("hset should update hash field");
        assert_digest_matches(&mut store);

        store
            .rpush(b"list", &[b"a".to_vec(), b"b".to_vec()], 0)
            .expect("rpush");
        store.lpushx(b"list", &[b"c".to_vec()], 0).expect("lpushx");
        store.rpoplpush(b"list", b"list2", 0).expect("rpoplpush");
        store
            .lmove(b"list2", b"list", b"LEFT", b"RIGHT", 0)
            .expect("lmove");
        assert_digest_matches(&mut store);

        store
            .sadd(b"set", &[b"a".to_vec(), b"b".to_vec()], 0)
            .expect("sadd");
        store.spop(b"set", 0).expect("spop");
        store
            .sadd(b"dst", &[b"z".to_vec()], 0)
            .expect("seed destination set");
        store.smove(b"set", b"dst", b"b", 0).expect("smove");
        assert_digest_matches(&mut store);

        store
            .zadd(b"z", &[(1.0, b"one".to_vec()), (2.0, b"two".to_vec())], 0)
            .expect("zadd");
        store
            .zpopmax_count(b"z", 1, 0)
            .expect("zpopmax_count should succeed");
        assert_digest_matches(&mut store);

        store
            .xadd(b"stream", (1, 0), &[(b"f".to_vec(), b"v".to_vec())], 0)
            .expect("xadd 1");
        store
            .xadd(b"stream", (2, 0), &[(b"f".to_vec(), b"v2".to_vec())], 0)
            .expect("xadd 2");
        store.xtrim(b"stream", 1, None, 0).expect("xtrim");
        assert_digest_matches(&mut store);
    }

    #[test]
    fn whole_entry_insert_marks_digest_stale_until_state_digest_recompute() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v1".to_vec(), None, 0);
        assert!(store.digest_stale);
        let inserted_digest = format!("{:016x}", store.state_digest_full_scan());
        assert_eq!(store.state_digest(), inserted_digest);
        assert!(!store.digest_stale);

        store.set(b"k".to_vec(), b"v2".to_vec(), None, 1);
        assert!(store.digest_stale);
        let replaced_digest = format!("{:016x}", store.state_digest_full_scan());
        assert_eq!(store.state_digest(), replaced_digest);
        assert!(!store.digest_stale);
    }

