    #[test]
    fn type_and_encoding_update_keyspace_stats_without_touching_lru() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 100);
        store.reset_info_stats();

        assert_eq!(store.key_type(b"k", 200), Some("string"));
        assert_eq!(store.stat_keyspace_hits, 1);
        assert_eq!(store.stat_keyspace_misses, 0);
        assert_eq!(
            store
                .entries
                .get(b"k".as_ref())
                .expect("type entry")
                .last_access_ms,
            100
        );

        assert_eq!(store.object_encoding(b"k", 250), Some("embstr"));
        assert_eq!(store.stat_keyspace_hits, 2);
        assert_eq!(
            store
                .entries
                .get(b"k".as_ref())
                .expect("encoding entry")
                .last_access_ms,
            100
        );

        assert_eq!(store.key_type(b"missing", 300), None);
        assert_eq!(store.stat_keyspace_misses, 1);
    }

    #[test]
    fn object_idletime_computes_idle_without_touching_lru_or_counting() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 100);
        store.reset_info_stats();

        // object_idletime computes the idle seconds and does NOT update the
        // entry's LRU access time. (frankenredis-934ax) It is also NON-counting:
        // upstream OBJECT IDLETIME does exactly ONE lookupKeyRead, which fr takes
        // in object_cmd's existence precheck (exists_no_touch); DEBUG OBJECT (the
        // other caller) must not bump stats at all. So the store method itself
        // leaves keyspace_hits/misses untouched.
        assert_eq!(store.object_idletime(b"k", 2_100), Some(2));
        assert_eq!(store.stat_keyspace_hits, 0);
        assert_eq!(store.stat_keyspace_misses, 0);
        assert_eq!(
            store
                .entries
                .get(b"k".as_ref())
                .expect("idletime entry")
                .last_access_ms,
            100
        );

        assert_eq!(store.object_idletime(b"missing", 2_100), None);
        assert_eq!(store.stat_keyspace_hits, 0);
        assert_eq!(store.stat_keyspace_misses, 0);

        // The single command-level count is taken by the existence precheck:
        // a present key bumps a hit, a missing key bumps a miss.
        store.reset_info_stats();
        assert!(store.exists_no_touch(b"k", 2_100));
        assert_eq!(store.stat_keyspace_hits, 1);
        assert!(!store.exists_no_touch(b"missing", 2_100));
        assert_eq!(store.stat_keyspace_misses, 1);
    }

    #[test]
    fn object_freq_tracks_lfu_accesses_and_preserves_lru_switch_behavior() {
        // (frankenredis-lfuinit) Updated for LFU_INIT_VAL=5 seeding.
        // When the maxmemory-policy is non-LFU, set() leaves lfu_freq=0
        // on the entry (the counter only matters under LFU). When the
        // policy is LFU, fresh keys seed at LFU_INIT_VAL=5 to match
        // upstream evict.h::LFU_INIT_VAL.
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 100);
        // No LFU policy yet → counter is 0 (set() else-branch).
        assert_eq!(store.object_freq(b"k", 150), Some(0));

        store.maxmemory_policy = MaxmemoryPolicy::AllkeysLfu;
        // Existing entry, LFU now enabled — counter still 0 from the
        // pre-LFU set() above.
        assert_eq!(store.object_freq(b"k", 200), Some(0));

        assert_eq!(store.get(b"k", 300).unwrap(), Some(b"v".to_vec()));
        assert_eq!(store.object_freq(b"k", 301), Some(1));

        // SET overwriting an existing entry under LFU bumps the counter
        // by 1 (matches upstream's existing-object code path).
        store.set(b"k".to_vec(), b"v2".to_vec(), None, 400);
        assert_eq!(store.object_freq(b"k", 401), Some(2));

        store.maxmemory_policy = MaxmemoryPolicy::AllkeysLru;
        assert_eq!(store.object_freq(b"k", 500), Some(2));
    }

    #[test]
    fn object_freq_seeds_at_lfu_init_val_on_fresh_set_under_lfu_policy() {
        // (frankenredis-lfuinit) Upstream evict.h::LFU_INIT_VAL = 5
        // gives newly-created objects a chance to compete before they
        // can be targeted for eviction. fr was seeding fresh keys at
        // 0 under LFU, so vendored 7.2.4's `OBJECT FREQ` returned 5
        // immediately after a SET while fr returned 0.
        let mut store = Store::new();
        store.maxmemory_policy = MaxmemoryPolicy::AllkeysLfu;
        store.set(b"k".to_vec(), b"v".to_vec(), None, 100);
        assert_eq!(store.object_freq(b"k", 150), Some(5));

        // VolatileLfu policy must also seed.
        store.maxmemory_policy = MaxmemoryPolicy::VolatileLfu;
        store.set(b"k2".to_vec(), b"v".to_vec(), None, 100);
        assert_eq!(store.object_freq(b"k2", 150), Some(5));
    }

    #[test]
    fn object_freq_log_increment_grows_sublinearly_with_default_factor() {
        // (frankenredis-lfulog) Upstream evict.c::LFULogIncr makes the
        // counter probabilistically incremented with
        // p = 1.0 / (baseval * log_factor + 1) where
        // baseval = max(0, counter - LFU_INIT_VAL). With log_factor=10
        // (upstream default), counter trajectory after many GETs grows
        // logarithmically — vendored reaches 8 after 50 GETs and stays
        // in the high teens after thousands of GETs. fr was bumping
        // naively (+1 each access) and counter would grow linearly.
        let mut store = Store::new();
        store.maxmemory_policy = MaxmemoryPolicy::AllkeysLfu;
        store.lfu_log_factor = 10;
        store.lfu_decay_time = 0; // disable decay so we measure pure incr
        store.set(b"k".to_vec(), b"v".to_vec(), None, 0);

        // Counter starts at LFU_INIT_VAL = 5, baseval = 0, p = 1.0
        // → first GET deterministically bumps to 6 even with random.
        assert_eq!(store.object_freq(b"k", 0), Some(5));
        assert_eq!(store.get(b"k", 0).unwrap(), Some(b"v".to_vec()));
        assert_eq!(store.object_freq(b"k", 0), Some(6));

        // 1000 more GETs: p drops to 1/(1*10+1)=~0.09 once baseval=1,
        // then 1/21, 1/31… so counter must grow but stay sub-linear.
        // Even with the LCG random sample, 1000 accesses can't push
        // beyond ~30 with default log_factor.
        for _ in 0..1000 {
            store.get(b"k", 0).unwrap();
        }
        let freq_after_1000 = store.object_freq(b"k", 0).expect("freq");
        assert!(
            (10..=40).contains(&freq_after_1000),
            "log-incr trajectory after 1000 GETs out of expected 10..=40 range: {freq_after_1000}"
        );

        // Saturated at 255 — bumping a saturated counter is a no-op.
        store.entries.get_mut(b"k".as_slice()).unwrap().lfu_freq = 255;
        store.get(b"k", 0).unwrap();
        assert_eq!(store.object_freq(b"k", 0), Some(255));
    }

    #[test]
    fn object_freq_decays_before_reporting_and_before_next_access_bump() {
        let mut store = Store::new();
        store.maxmemory_policy = MaxmemoryPolicy::AllkeysLfu;
        store.lfu_decay_time = 1;
        store.set(b"k".to_vec(), b"v".to_vec(), None, 0);

        // (frankenredis-lfuinit) Fresh SET under LFU now seeds at 5.
        // Subsequent GET bumps to 6; decay across one minute drops
        // back to 5 (one decay_time period).
        assert_eq!(store.get(b"k", 1).unwrap(), Some(b"v".to_vec()));
        assert_eq!(store.object_freq(b"k", 2), Some(6));
        assert_eq!(store.object_freq(b"k", 60_000), Some(5));

        assert_eq!(store.get(b"k", 60_001).unwrap(), Some(b"v".to_vec()));
        assert_eq!(store.object_freq(b"k", 60_002), Some(6));

        store.lfu_decay_time = 2;
        assert_eq!(store.object_freq(b"k", 179_999), Some(6));
        assert_eq!(store.object_freq(b"k", 180_000), Some(5));
    }

