        store.set(encode_db_key(0, b"soon"), b"2".to_vec(), Some(50), 0);
        store.set(encode_db_key(0, b"later"), b"3".to_vec(), Some(500), 0);

        let result = store.keys_matching_in_db(0, b"*", 100);
