    #[test]
    fn dbsize_counts_live_keys() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), None, 0);
        store.set(b"b".to_vec(), b"2".to_vec(), Some(100), 0);
        assert_eq!(store.dbsize_in_db(0), 2);

        // dbsize is O(1) and does not actively reap expired keys.
        // It should still return 2 even if 'b' is logically expired,
        // until 'b' is actively or lazily reaped.
        assert_eq!(store.dbsize_in_db(0), 2);

        // Lazy reap
        store.get(b"b", 200).unwrap();
        assert_eq!(store.dbsize_in_db(0), 1);
    }

    #[test]
    fn flushdb_clears_all() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), None, 0);
        store.set(b"b".to_vec(), b"2".to_vec(), None, 0);
        store.flushdb();
        assert!(store.is_empty());
    }

    #[test]
    fn flushdb_clears_ordered_keys_and_hash_field_expires() {
        // (frankenredis-ss2k0) Real bug: flushdb cleared `entries` but
        // not `ordered_keys`, so KEYS/SCAN/RANDOMKEY surfaced ghost
        // key names after FLUSHALL — clients saw "the database is
        // empty (DBSIZE=0) but RANDOMKEY returned a name". hash_field_
        // expires was similarly orphaned, breaking HTTL on hashes
        // re-created with the same key after a flush.
        let mut store = Store::new();
        store.set(b"alpha".to_vec(), b"1".to_vec(), None, 0);
        store.set(b"beta".to_vec(), b"2".to_vec(), None, 0);
        store
            .hset(b"h", b"f".to_vec(), b"v".to_vec(), 0)
            .expect("hset");
        // Set a per-field TTL so hash_field_expires is non-empty.
        store
            .hash_field_expires
            .insert((b"h".to_vec(), b"f".to_vec()), 10_000);

        store.flushdb();

        // All visible state is empty.
        assert!(store.is_empty());
        assert!(store.ordered_keys.is_empty(), "ordered_keys must be empty");
        assert!(
            store.hash_field_expires.is_empty(),
            "hash_field_expires must be empty after flush"
        );

        // KEYS/SCAN/RANDOMKEY surface contracts: nothing to enumerate.
        assert_eq!(
            store.keys_matching(b"*", 0),
            Vec::<Vec<u8>>::new(),
            "KEYS * after flush must be empty"
        );
    }

    #[test]
    fn swap_prefixes_preserves_hash_field_ttls() {
        // (frankenredis-sdmwz) SWAPDB silently dropped per-field hash
        // TTLs because internal_entries_remove cleared
        // hash_field_expires for the source key but the swap loop
        // never re-inserted them at the destination prefix. Pin the
        // round-trip: a hash with field TTLs swapped from the "db0:"
        // prefix to "db1:" must surface the same TTLs at the new key.
        let mut store = Store::new();
        store
            .hset(b"db0:h", b"f".to_vec(), b"v".to_vec(), 0)
            .expect("hset");
        store
            .hash_field_expires
            .insert((b"db0:h".to_vec(), b"f".to_vec()), 99_999);
        // Also seed an unrelated key in the right prefix to ensure we
        // don't migrate ttls across keys that should stay in place.
        store
            .hset(b"db1:other", b"x".to_vec(), b"y".to_vec(), 0)
            .expect("hset other");

        let touched = store.swap_prefixes(b"db0:", b"db1:");
        assert!(touched >= 2, "swap should touch both source + dst keys");

        // Field TTL must follow the hash to its new key.
        assert_eq!(
            store
                .hash_field_expires
                .get(&(b"db1:h".to_vec(), b"f".to_vec())),
            Some(&99_999),
            "field TTL must follow the hash through SWAPDB"
        );
        assert!(
            !store
                .hash_field_expires
                .contains_key(&(b"db0:h".to_vec(), b"f".to_vec())),
            "old (db0:h, f) row must be gone"
        );
    }

    #[test]
    fn command_histogram_record_canonicalizes_and_reports_ab_ratio() {
        use super::{CommandHistogramTracker, CommandRecordKind};
        // Case-insensitive canonicalization: SET/set/Set all land on "set", and
        // the count aggregates (byte-identical to the to_ascii_lowercase path).
        // (frankenredis-igx7w)
        let mut t = CommandHistogramTracker::default();
        t.record_with_kind("SET", 10, CommandRecordKind::Success);
        t.record_with_kind("set", 20, CommandRecordKind::Success);
        t.record_with_kind("Set", 30, CommandRecordKind::Success);
        t.record_with_kind("GET", 5, CommandRecordKind::Success);
        let all = t.all();
        let keys: Vec<&str> = all.iter().map(|(k, _)| *k).collect();
        assert_eq!(keys, vec!["get", "set"], "canonical lowercase keys");
        // Long-name (>40 bytes) fallback path stays correct.
        let long = "x".repeat(60);
        let long_upper = long.to_uppercase();
        t.record_with_kind(&long_upper, 1, CommandRecordKind::Success);
        assert!(t.get(&long).is_some(), "long-name fallback canonicalizes");
        // Container subcommand fullnames ("config|get") canonicalize too.
        t.record_with_kind("CONFIG|GET", 1, CommandRecordKind::Success);
        assert!(t.get("config|get").is_some());

        // A/B: per-command record() — stack-buffer probe vs the old
        // entry(to_ascii_lowercase()) heap-allocating path.
        fn old_record(t: &mut CommandHistogramTracker, command: &str) {
            // mirror the prior implementation (allocates every call)
            t.record_with_kind(&command.to_ascii_lowercase(), 1, CommandRecordKind::Success);
        }
        let cmds = [
            "SET", "GET", "HSET", "INCR", "LPUSH", "ZADD", "EXPIRE", "MGET",
        ];
        let reps = 2_000_000usize;
        let mut t1 = CommandHistogramTracker::default();
        let t0 = std::time::Instant::now();
        for i in 0..reps {
            old_record(&mut t1, std::hint::black_box(cmds[i & 7]));
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(&t1);
        let mut t2 = CommandHistogramTracker::default();
        let s0 = std::time::Instant::now();
        for i in 0..reps {
            t2.record_with_kind(
                std::hint::black_box(cmds[i & 7]),
                1,
                CommandRecordKind::Success,
            );
        }
        let new_ns = s0.elapsed().as_nanos().max(1);
        std::hint::black_box(&t2);
        let ratio = old_ns as f64 / new_ns as f64;
        println!(
            "command-stats record A/B (x{reps}): old(alloc)={old_ns}ns new(stackbuf)={new_ns}ns ratio={ratio:.2}x"
        );
    }

    #[test]
    fn glob_match_patterns() {
        use super::glob_match;
        assert!(glob_match(b"*", b"anything"));
        assert!(glob_match(b"h?llo", b"hello"));
        assert!(glob_match(b"h?llo", b"hallo"));
        assert!(!glob_match(b"h?llo", b"hllo"));
        assert!(glob_match(b"h[ae]llo", b"hello"));
        assert!(glob_match(b"h[ae]llo", b"hallo"));
        assert!(!glob_match(b"h[ae]llo", b"hillo"));
        assert!(glob_match(b"h[^e]llo", b"hallo"));
        assert!(!glob_match(b"h[^e]llo", b"hello"));
        assert!(glob_match(b"h[a-e]llo", b"hcllo"));
        assert!(!glob_match(b"h[a-e]llo", b"hzllo"));
        assert!(glob_match(b"foo*bar", b"fooXYZbar"));
        assert!(glob_match(b"foo*bar", b"foobar"));
        assert!(glob_match(b"\\*literal", b"*literal"));
        assert!(glob_match(b"[z-a]", b"m"));
        assert!(glob_match(b"[\\-]", b"-"));
        assert!(glob_match(b"[a-]", b"]"));
        assert!(glob_match(b"[a-]", b"a"));
        assert!(glob_match(b"[abc", b"a"));
        assert!(glob_match(b"[abc", b"c"));
        assert!(!glob_match(b"[abc", b"["));
        assert!(glob_match(b"[!a]", b"!"));
        assert!(glob_match(b"[!a]", b"a"));
        assert!(!glob_match(b"[!a]", b"b"));
        assert!(!glob_match(b"[literal", b"[literal"));
        assert!(!glob_match(b"[a-", b"[a-"));
        assert!(!glob_match(b"[literal", b"literal"));
    }

