    /// XTRIM ... LIMIT n cap: when the requested removal count
    /// exceeds the LIMIT, only `n` oldest entries are removed and
    /// the rest survive, even though the resulting stream length
    /// stays above `max_len`. Mirrors upstream
    /// t_stream.c::streamTrim's LIMIT path semantics, which the
    /// approximate (`~`) trim form caps at the user-supplied bound.
    #[test]
    fn stream_xtrim_maxlen_with_limit_caps_removal() {
        let mut store = Store::new();
        for i in 0..10u64 {
            store
                .xadd(b"s", (1000 + i, 0), &[(b"f".to_vec(), vec![i as u8])], 0)
                .unwrap();
        }
        // Without LIMIT: trims all the way down to max_len=2 (8
        // removals).
        let mut bare = Store::new();
        for i in 0..10u64 {
            bare.xadd(b"s", (1000 + i, 0), &[(b"f".to_vec(), vec![i as u8])], 0)
                .unwrap();
        }
        assert_eq!(bare.xtrim(b"s", 2, None, 0).unwrap(), 8);
        assert_eq!(bare.xlen(b"s", 0).unwrap(), 2);

        // With LIMIT=3: cap removal at 3 even though 8 entries
        // exceed max_len. Stream length remains 7, NOT 2.
        let removed = store.xtrim(b"s", 2, Some(3), 0).unwrap();
        assert_eq!(removed, 3);
        assert_eq!(store.xlen(b"s", 0).unwrap(), 7);

        // The removed entries must be the OLDEST three — verify
        // the surviving range starts at id (1003, 0).
        let remaining = store
            .xrange(b"s", (0, 0), (u64::MAX, u64::MAX), None, 0)
            .unwrap();
        assert_eq!(remaining[0].0, (1003, 0));
        assert_eq!(remaining.last().unwrap().0, (1009, 0));
    }

    /// Same cap semantics for the MINID variant.
    #[test]
    fn stream_xtrim_minid_with_limit_caps_removal() {
        let mut store = Store::new();
        for i in 0..10u64 {
            store
                .xadd(b"s", (1000 + i, 0), &[(b"f".to_vec(), vec![i as u8])], 0)
                .unwrap();
        }
        // MINID=1006 would normally remove ids (1000..=1005) = 6
        // entries. Cap at 2 → only the 2 oldest go.
        let removed = store.xtrim_minid(b"s", (1006, 0), Some(2), 0).unwrap();
        assert_eq!(removed, 2);
        let remaining = store
            .xrange(b"s", (0, 0), (u64::MAX, u64::MAX), None, 0)
            .unwrap();
        assert_eq!(remaining[0].0, (1002, 0));
    }

    /// MINID approximate (~) trim is node-boundary aware: it evicts whole
    /// REDIS_STREAM_NODE_MAX_ENTRIES-sized head nodes only while the node's last
    /// id < threshold, leaving a node that straddles the threshold intact.
    /// (frankenredis-8t4vl)
    #[test]
    fn stream_xtrim_minid_approx_evicts_whole_nodes_8t4vl() {
        let mut store = Store::new();
        // 250 entries -> nodes [1..=100], [101..=200], [201..=250].
        for i in 1..=250u64 {
            store
                .xadd(b"s", (i, 0), &[(b"f".to_vec(), vec![0u8])], 0)
                .unwrap();
        }
        // The command layer maps an un-LIMITed `~` to this default cap
        // (100 * stream-node-max-entries, the node size being 100).
        let cap = Some(100 * 100);

        // Threshold inside the first node: node0 last id = 100 NOT < 100 -> keep.
        assert_eq!(store.xtrim_minid_approx(b"s", (100, 0), cap, 0).unwrap(), 0);
        // Threshold just past node0: last id 100 < 101 -> drop the whole node.
        // node1 last id 200 NOT < 150 -> stop. Removes exactly 100.
        assert_eq!(
            store.xtrim_minid_approx(b"s", (150, 0), cap, 0).unwrap(),
            100
        );
        assert_eq!(store.xlen(b"s", 0).unwrap(), 150);
        assert_eq!(
            store
                .xrange(b"s", (0, 0), (u64::MAX, u64::MAX), Some(1), 0)
                .unwrap()[0]
                .0,
            (101, 0)
        );

        // A threshold above every id removes all remaining nodes (incl. the
        // partial tail node) — unlike MAXLEN approx which keeps the tail.
        assert_eq!(
            store.xtrim_minid_approx(b"s", (10_000, 0), cap, 0).unwrap(),
            150
        );
        assert_eq!(store.xlen(b"s", 0).unwrap(), 0);
    }

    /// A LIMIT smaller than a node evicts nothing (whole-node granularity), and
    /// the cap follows upstream's `(deleted + entries) > limit` break.
    #[test]
    fn stream_xtrim_minid_approx_limit_is_whole_node_8t4vl() {
        let mut store = Store::new();
        for i in 1..=250u64 {
            store
                .xadd(b"s", (i, 0), &[(b"f".to_vec(), vec![0u8])], 0)
                .unwrap();
        }
        // All three nodes qualify (threshold 10000), but LIMIT 150 only allows
        // the first node (0+100<=150); the second would make 200>150 -> stop.
        assert_eq!(
            store
                .xtrim_minid_approx(b"s", (10_000, 0), Some(150), 0)
                .unwrap(),
            100
        );
        // LIMIT 50 < node size -> evict nothing.
        assert_eq!(
            store
                .xtrim_minid_approx(b"s", (10_000, 0), Some(50), 0)
                .unwrap(),
            0
        );
        // limit == None (the LIMIT 0 / unbounded form) -> evict everything.
        assert_eq!(
            store
                .xtrim_minid_approx(b"s", (10_000, 0), None, 0)
                .unwrap(),
            150
        );
    }

    /// LIMIT=0 must be a true no-op even when entries exceed
    /// max_len — exercises the boundary where the approximate-trim
    /// path is asked to do zero work.
    #[test]
    fn stream_xtrim_with_limit_zero_is_noop() {
        let mut store = Store::new();
        for i in 0..5u64 {
            store
                .xadd(b"s", (1000 + i, 0), &[(b"f".to_vec(), vec![i as u8])], 0)
                .unwrap();
        }
        let removed = store.xtrim(b"s", 1, Some(0), 0).unwrap();
        assert_eq!(removed, 0);
        assert_eq!(store.xlen(b"s", 0).unwrap(), 5);
    }

    #[test]
    fn stream_xread_returns_entries_after_id_and_respects_count() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1000, 0), &[(b"f1".to_vec(), b"v1".to_vec())], 0)
            .unwrap();
        store
            .xadd(b"s", (1000, 1), &[(b"f2".to_vec(), b"v2".to_vec())], 0)
            .unwrap();
        store
            .xadd(b"s", (1001, 0), &[(b"f3".to_vec(), b"v3".to_vec())], 0)
            .unwrap();

        let all_after = store.xread(b"s", (1000, 0), None, 0).unwrap();
        assert_eq!(all_after.len(), 2);
        assert_eq!(all_after[0].0, (1000, 1));
        assert_eq!(all_after[1].0, (1001, 0));

        let limited = store.xread(b"s", (0, 0), Some(1), 0).unwrap();
        assert_eq!(limited.len(), 1);
        assert_eq!(limited[0].0, (1000, 0));

        let none = store.xread(b"s", (u64::MAX, u64::MAX), None, 0).unwrap();
        assert!(none.is_empty());
    }

