    /// (frankenredis f80 long-double parity) INCRBYFLOAT/HINCRBYFLOAT compute in
    /// x87 80-bit long double then format `%.17Lf`. These golden results — which
    /// surface f80 rounding noise an f64 path cannot reproduce — were captured
    /// from vendored redis 7.2.4 and exercised against it across ~35k fuzzed
    /// operations with zero divergence.
    #[test]
    fn incrbyfloat_long_double_matches_vendored() {
        let cases: &[(&str, &str, &str)] = &[
            ("694.867474", "-764.162593", "-69.29511899999999996"),
            (
                "3.14159265358979323846",
                "-827064.8205435034",
                "-827061.67895084981023501",
            ),
            ("0.1", "0.2", "0.3"),
            ("486.29332", "0.0001", "486.29341999999999999"),
            ("0", "0.1", "0.1"),
            ("100000000000000000.5", "1e-300", "100000000000000000.5"),
            (
                "3536970797.0994870001450181",
                "0.1",
                "3536970797.19948700023815036",
            ),
            ("-0.5", "0.5", "0"),
            ("1e-300", "1", "1"),
            ("5", "3", "8"),
            ("1.5", "2.5", "4"),
            ("0.0001", "0.0002", "0.0003"),
        ];
        for (cur, delta, expected) in cases {
            let mut store = Store::new();
            store.set(b"k".to_vec(), cur.as_bytes().to_vec(), None, 0);
            let got = store
                .incrbyfloat_text(
                    b"k",
                    delta.as_bytes(),
                    delta.parse::<f64>().unwrap_or(0.0),
                    0,
                )
                .unwrap();
            assert_eq!(
                got,
                expected.as_bytes(),
                "INCRBYFLOAT {cur} + {delta}: got {:?}",
                String::from_utf8_lossy(&got)
            );
            // HINCRBYFLOAT shares the long-double path.
            let mut hstore = Store::new();
            hstore
                .hset(b"h", b"f".to_vec(), cur.as_bytes().to_vec(), 0)
                .unwrap();
            let hgot = hstore
                .hincrbyfloat_text(
                    b"h",
                    b"f",
                    delta.as_bytes(),
                    delta.parse::<f64>().unwrap_or(0.0),
                    0,
                )
                .unwrap();
            assert_eq!(hgot, expected.as_bytes(), "HINCRBYFLOAT {cur} + {delta}");
        }
    }

    /// (frankenredis f80 decimal range) Values beyond f64 range but within the
    /// x87 80-bit long double range (~1.19e4932) — e.g. "1e500" — are accepted
    /// and computed in f80 (previously rejected as "not a valid float" by the
    /// 400-digit cap / f64 fallback). Verified byte-exact vs redis 7.2.4 by fuzz.
    #[test]
    fn incrbyfloat_accepts_f80_decimal_range() {
        for delta in ["1e500", "1e4000", "1e4932"] {
            let mut store = Store::new();
            store.set(b"k".to_vec(), b"0".to_vec(), None, 0);
            let got = store
                .incrbyfloat_text(b"k", delta.as_bytes(), f64::INFINITY, 0)
                .unwrap_or_else(|e| panic!("{delta} should be accepted, got {e:?}"));
            assert!(
                got.iter().all(u8::is_ascii_digit) && got.len() > 300,
                "{delta} -> {:?}",
                String::from_utf8_lossy(&got)
            );
        }
        // Beyond the f80 range is still rejected (overflow).
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"0".to_vec(), None, 0);
        assert!(
            store
                .incrbyfloat_text(b"k", b"1e5000", f64::INFINITY, 0)
                .is_err()
        );
    }

