    fn append_raw_dump_bulk(buf: &mut Vec<u8>, data: &[u8]) {
        encode_length(buf, data.len());
        buf.extend_from_slice(data);
    }

    fn encode_test_ziplist_strings(entries: &[&[u8]]) -> Option<Vec<u8>> {
        let mut body = Vec::new();
        let mut prev_len = 0usize;
        let mut tail_offset = 10usize;
        for entry in entries {
            tail_offset = 10usize.checked_add(body.len())?;
            let entry_start = body.len();
            if prev_len < 254 {
                body.push(u8::try_from(prev_len).ok()?);
            } else {
                body.push(0xFE);
                body.extend_from_slice(&u32::try_from(prev_len).ok()?.to_le_bytes());
            }

            if entry.len() <= 0x3F {
                body.push(u8::try_from(entry.len()).ok()?);
            } else if entry.len() <= 0x3FFF {
                body.push(0x40 | u8::try_from(entry.len() >> 8).ok()?);
                body.push(u8::try_from(entry.len() & 0xFF).ok()?);
            } else {
                body.push(0x80);
                body.extend_from_slice(&u32::try_from(entry.len()).ok()?.to_be_bytes());
            }
            body.extend_from_slice(entry);
            prev_len = body.len().checked_sub(entry_start)?;
        }
        body.push(0xFF);

        let total_bytes = 10usize.checked_add(body.len())?;
        let mut ziplist = Vec::with_capacity(total_bytes);
        ziplist.extend_from_slice(&u32::try_from(total_bytes).ok()?.to_le_bytes());
        ziplist.extend_from_slice(&u32::try_from(tail_offset).ok()?.to_le_bytes());
        ziplist.extend_from_slice(
            &u16::try_from(entries.len())
                .unwrap_or(u16::MAX)
                .to_le_bytes(),
        );
        ziplist.extend_from_slice(&body);
        Some(ziplist)
    }

    fn encode_test_zipmap(pairs: &[(&[u8], &[u8])]) -> Option<Vec<u8>> {
        let mut zm = Vec::new();
        zm.push(if pairs.len() < 254 {
            u8::try_from(pairs.len()).ok()?
        } else {
            254
        });
        for (key, value) in pairs {
            if key.len() < 254 {
                zm.push(u8::try_from(key.len()).ok()?);
            } else {
                zm.push(254);
                zm.extend_from_slice(&u32::try_from(key.len()).ok()?.to_be_bytes());
            }
            zm.extend_from_slice(key);
            if value.len() < 254 {
                zm.push(u8::try_from(value.len()).ok()?);
            } else {
                zm.push(254);
                zm.extend_from_slice(&u32::try_from(value.len()).ok()?.to_be_bytes());
            }
            zm.push(0);
            zm.extend_from_slice(value);
        }
        zm.push(255);
        Some(zm)
    }

    fn byte_vecs_match(actual: &[Vec<u8>], expected: &[&[u8]]) -> bool {
        matches!(actual.len().cmp(&expected.len()), std::cmp::Ordering::Equal)
            && actual
                .iter()
                .zip(expected)
                .all(|(actual_item, expected_item)| {
                    matches!(
                        actual_item.as_slice().cmp(expected_item),
                        std::cmp::Ordering::Equal
                    )
                })
    }

    #[test]
    fn dump_payload_uses_upstream_container_tags() {
        let mut store = Store::new();
        store
            .rpush(b"list", &[b"a".to_vec(), b"b".to_vec()], 100)
            .unwrap();
        store.sadd(b"set", &[b"a".to_vec()], 100).unwrap();
        store.sadd(b"intset", &[b"1".to_vec()], 100).unwrap();
        store
            .hset(b"hash", b"f".to_vec(), b"v".to_vec(), 100)
            .unwrap();
        store.zadd(b"zset", &[(1.5, b"a".to_vec())], 100).unwrap();
        // raw_set/raw_zset use 129 to push past their 128-entry listpack
        // threshold; raw_hash uses 513 to clear hash_max_listpack_entries
        // (512, upstream Redis 7.2 default).
        for i in 0..129 {
            store
                .sadd(b"raw_set", &[format!("member-{i}").into_bytes()], 100)
                .unwrap();
        }
        for i in 0..513 {
            store
                .hset(
                    b"raw_hash",
                    format!("field-{i}").into_bytes(),
                    b"v".to_vec(),
                    100,
                )
                .unwrap();
        }
        let raw_zset_members: Vec<(f64, Vec<u8>)> = (0..129)
            .map(|i| (f64::from(i), format!("member-{i}").into_bytes()))
            .collect();
        store.zadd(b"raw_zset", &raw_zset_members, 100).unwrap();

        assert_eq!(
            store.dump_key(b"list", 100).unwrap()[0],
            RDB_TYPE_LIST_QUICKLIST_2
        );
        assert_eq!(
            store.dump_key(b"intset", 100).unwrap()[0],
            RDB_TYPE_SET_INTSET
        );
        assert_eq!(
            store.dump_key(b"set", 100).unwrap()[0],
            RDB_TYPE_SET_LISTPACK
        );
        assert_eq!(
            store.dump_key(b"hash", 100).unwrap()[0],
            RDB_TYPE_HASH_LISTPACK
        );
        assert_eq!(
            store.dump_key(b"zset", 100).unwrap()[0],
            RDB_TYPE_ZSET_LISTPACK
        );
        assert_eq!(store.dump_key(b"raw_set", 100).unwrap()[0], RDB_TYPE_SET);
        assert_eq!(store.dump_key(b"raw_hash", 100).unwrap()[0], RDB_TYPE_HASH);
        assert_eq!(
            store.dump_key(b"raw_zset", 100).unwrap()[0],
            RDB_TYPE_ZSET_2
        );
    }

    #[test]
    fn dump_zset2_uses_upstream_descending_skiplist_order() {
        let mut store = Store::new();
        store.zset_max_listpack_entries = 2;
        store
            .zadd(
                b"z",
                &[
                    (2.0, b"alpha".to_vec()),
                    (3.0, b"gamma".to_vec()),
                    (2.0, b"beta".to_vec()),
                ],
                100,
            )
            .unwrap();

        let payload = store.dump_key(b"z", 100).unwrap();
        assert_eq!(payload[0], RDB_TYPE_ZSET_2);
        let data_end = payload.len() - DUMP_TRAILER_LEN;
        let mut cursor = 1;
        let (count, consumed) = decode_length(&payload, cursor).unwrap();
        cursor += consumed;
        assert_eq!(count, 3);

        let mut dumped = Vec::new();
        for _ in 0..count {
            let (member, consumed) = decode_rdb_string(&payload, cursor, data_end).unwrap();
            cursor += consumed;
            assert!(cursor + 8 <= data_end);
            let mut score_bytes = [0; 8];
            score_bytes.copy_from_slice(&payload[cursor..cursor + 8]);
            let score = f64::from_le_bytes(score_bytes);
            cursor += 8;
            dumped.push((member, score));
        }
        assert_eq!(cursor, data_end);
        assert_eq!(
            dumped,
            vec![
                (b"gamma".to_vec(), 3.0),
                (b"beta".to_vec(), 2.0),
                (b"alpha".to_vec(), 2.0),
            ]
        );
    }

    #[test]
    fn restore_accepts_legacy_zset_with_textual_scores() {
        let mut body = vec![RDB_TYPE_ZSET];
        encode_length(&mut body, 2);
        append_raw_dump_bulk(&mut body, b"one");
        body.push(1);
        body.extend_from_slice(b"1");
        append_raw_dump_bulk(&mut body, b"half");
        body.push(3);
        body.extend_from_slice(b"0.5");
        let payload = append_dump_footer(body);

        let mut store = Store::new();
        assert_eq!(store.restore_key(b"z", 0, &payload, false, 100), Ok(()));

        assert_eq!(store.zscore(b"z", b"one", 100), Ok(Some(1.0)));
        assert_eq!(store.zscore(b"z", b"half", 100), Ok(Some(0.5)));
        assert_eq!(
            store.zrange(b"z", 0, -1, 100),
            Ok(vec![b"half".to_vec(), b"one".to_vec()])
        );
    }

