    #[test]
    fn dump_restore_stream_round_trip() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1, 0), &[(b"name".to_vec(), b"alice".to_vec())], 100)
            .unwrap();
        store
            .xadd(
                b"s",
                (2, 0),
                &[
                    (b"name".to_vec(), b"bob".to_vec()),
                    (b"age".to_vec(), b"30".to_vec()),
                ],
                100,
            )
            .unwrap();
        store.xgroup_create(b"s", b"g", (0, 0), false, 100).unwrap();
        let read = store
            .xreadgroup(
                b"s",
                b"g",
                b"alice",
                StreamGroupReadOptions {
                    cursor: StreamGroupReadCursor::NewEntries,
                    noack: false,
                    count: None,
                },
                150,
            )
            .unwrap()
            .expect("stream group read");
        assert_eq!(read.len(), 2);
        let payload = store.dump_key(b"s", 100).unwrap();
        assert_eq!(payload[0], RDB_TYPE_STREAM_LISTPACKS_3);
        let mut store2 = Store::new();
        store2.restore_key(b"s", 0, &payload, false, 100).unwrap();
        let entries = store2
            .xrange(b"s", (0, 0), (u64::MAX, u64::MAX), None, 100)
            .unwrap();
        assert_eq!(entries.len(), 2);
        assert_eq!(entries[0].0, (1, 0));
        assert_eq!(entries[0].1, vec![(b"name".to_vec(), b"alice".to_vec())]);
        assert_eq!(entries[1].0, (2, 0));
        let groups = store2.xinfo_groups(b"s", 100).unwrap().expect("groups");
        // DUMP/RESTORE round-trips entries-read alongside other group
        // metadata. (frankenredis-ic8v)
        assert_eq!(groups, vec![(b"g".to_vec(), 1, 2, (2, 0), Some(2))]);
        let pending = store2
            .xpending_summary(b"s", b"g", 200)
            .unwrap()
            .expect("pending summary");
        assert_eq!(pending.0, 2);
        assert_eq!(pending.1, Some((1, 0)));
        assert_eq!(pending.2, Some((2, 0)));
        assert_eq!(pending.3, vec![(b"alice".to_vec(), 2)]);
    }

    #[test]
    fn dump_restore_stream_preserves_max_deleted_entry_id() {
        let mut store = Store::new();
        store
            .xadd(
                b"s",
                (1000, 0),
                &[(b"name".to_vec(), b"alice".to_vec())],
                100,
            )
            .unwrap();
        store
            .xadd(b"s", (1000, 1), &[(b"name".to_vec(), b"bob".to_vec())], 100)
            .unwrap();
        store
            .xadd(
                b"s",
                (1001, 0),
                &[(b"name".to_vec(), b"cara".to_vec())],
                100,
            )
            .unwrap();
        assert_eq!(store.xdel(b"s", &[(1000, 1)], 100).unwrap(), 1);
        assert_eq!(store.stream_max_deleted_id(b"s"), Some((1000, 1)));

        let payload = store.dump_key(b"s", 100).unwrap();
        assert_eq!(payload[0], RDB_TYPE_STREAM_LISTPACKS_3);

        let mut restored = Store::new();
        restored.restore_key(b"s", 0, &payload, false, 100).unwrap();
        assert_eq!(restored.stream_max_deleted_id(b"s"), Some((1000, 1)));
        let entries = restored
            .xrange(b"s", (0, 0), (u64::MAX, u64::MAX), None, 100)
            .unwrap();
        assert_eq!(entries.len(), 2);
        assert_eq!(entries[0].0, (1000, 0));
        assert_eq!(entries[1].0, (1001, 0));
    }

    #[test]
    fn restore_rejects_duplicate_stream_groups_and_consumers() -> Result<(), String> {
        fn group(name: &[u8], consumers: &[&[u8]]) -> fr_persist::RdbStreamConsumerGroup {
            fr_persist::RdbStreamConsumerGroup {
                name: name.to_vec(),
                last_delivered_id_ms: 1,
                last_delivered_id_seq: 0,
                entries_read: Some(1),
                consumers: consumers
                    .iter()
                    .map(|consumer| fr_persist::RdbStreamConsumer::named(consumer.to_vec()))
                    .collect(),
                pending: Vec::new(),
            }
        }

        fn stream_dump_with_groups(
            groups: Vec<fr_persist::RdbStreamConsumerGroup>,
        ) -> Result<Vec<u8>, String> {
            let entries = vec![(1, 0, vec![(b"f".to_vec(), b"v".to_vec())])];
            let stream_payload = fr_persist::encode_upstream_stream_listpacks3_payload(
                &entries,
                Some((1, 0)),
                &groups,
                Some(1),
                None,
            )
            .ok_or_else(|| "stream payload encoding failed".to_string())?;
            let mut body = vec![RDB_TYPE_STREAM_LISTPACKS_3];
            body.extend_from_slice(&stream_payload);
            Ok(append_dump_footer(body))
        }

        fn expect_invalid_restore(label: &[u8], payload: &[u8]) -> Result<(), String> {
            let mut store = Store::new();
            match store.restore_key(label, 0, payload, false, 100) {
                Err(StoreError::InvalidDumpPayload) => Ok(()),
                other => Err(format!(
                    "stream dump with duplicate metadata should fail, got {other:?}"
                )),
            }
        }

        let duplicate_groups = stream_dump_with_groups(vec![
            group(b"g", &[b"alice".as_slice()]),
            group(b"g", &[b"bob".as_slice()]),
        ])?;
        expect_invalid_restore(b"duplicate-groups", &duplicate_groups)?;

        let duplicate_consumers = stream_dump_with_groups(vec![group(
            b"g",
            &[b"alice".as_slice(), b"alice".as_slice()],
        )])?;
        expect_invalid_restore(b"duplicate-consumers", &duplicate_consumers)?;

        let valid_payload =
            stream_dump_with_groups(vec![group(b"g", &[b"alice".as_slice(), b"bob".as_slice()])])?;
        let mut store = Store::new();
        store
            .restore_key(b"valid", 0, &valid_payload, false, 100)
            .map_err(|err| format!("valid stream groups must restore: {err:?}"))?;

        Ok(())
    }

    #[test]
    fn restore_rejects_duplicate_stream_pending_entry_ids() -> Result<(), String> {
        fn pending_entry(
            consumer: &[u8],
            deliveries: u64,
            last_delivered_ms: u64,
        ) -> fr_persist::RdbStreamPendingEntry {
            fr_persist::RdbStreamPendingEntry {
                entry_id_ms: 1,
                entry_id_seq: 0,
                consumer: consumer.to_vec(),
                deliveries,
                last_delivered_ms,
            }
        }

        fn stream_dump_with_pending(
            pending: Vec<fr_persist::RdbStreamPendingEntry>,
        ) -> Result<Vec<u8>, String> {
            let entries = vec![(1, 0, vec![(b"f".to_vec(), b"v".to_vec())])];
            let groups = vec![fr_persist::RdbStreamConsumerGroup {
                name: b"g".to_vec(),
                last_delivered_id_ms: 1,
                last_delivered_id_seq: 0,
                entries_read: Some(1),
                consumers: vec![fr_persist::RdbStreamConsumer::named(b"alice".to_vec())],
                pending,
            }];
            let stream_payload = fr_persist::encode_upstream_stream_listpacks3_payload(
                &entries,
                Some((1, 0)),
                &groups,
                Some(1),
                None,
            )
            .ok_or_else(|| "stream payload encoding failed".to_string())?;
            let mut body = vec![RDB_TYPE_STREAM_LISTPACKS_3];
            body.extend_from_slice(&stream_payload);
            Ok(append_dump_footer(body))
        }

        let duplicate_payload = stream_dump_with_pending(vec![
            pending_entry(b"alice", 1, 100),
            pending_entry(b"alice", 2, 200),
        ])?;
        let mut duplicate_store = Store::new();
        match duplicate_store.restore_key(b"duplicate-pel", 0, &duplicate_payload, false, 100) {
            Err(StoreError::InvalidDumpPayload) => {}
            other => {
                return Err(format!(
                    "duplicate stream PEL entry IDs should fail restore, got {other:?}"
                ));
            }
        }

        let valid_payload = stream_dump_with_pending(vec![pending_entry(b"alice", 1, 100)])?;
        let mut valid_store = Store::new();
        valid_store
            .restore_key(b"valid-pel", 0, &valid_payload, false, 100)
            .map_err(|err| format!("valid stream PEL should restore: {err:?}"))?;
        let summary = valid_store
            .xpending_summary(b"valid-pel", b"g", 100)
            .map_err(|err| format!("pending summary should succeed: {err:?}"))?
            .ok_or_else(|| "pending summary should be present".to_string())?;
        if summary.0 != 1 {
            return Err(format!(
                "valid stream PEL should contain one entry, got {summary:?}"
            ));
        }

        Ok(())
    }

    #[test]
    fn restore_rejects_duplicate_stream_entry_ids() -> Result<(), String> {
        fn stream_dump_with_entries(
            entries: Vec<fr_persist::StreamEntry>,
        ) -> Result<Vec<u8>, String> {
            let entries_added = u64::try_from(entries.len())
                .map_err(|_| "stream entry count exceeded u64".to_string())?;
            let stream_payload = fr_persist::encode_upstream_stream_listpacks3_payload(
                &entries,
                entries.last().map(|entry| (entry.0, entry.1)),
                &[],
                Some(entries_added),
                None,
            )
            .ok_or_else(|| "stream payload encoding failed".to_string())?;
            let mut body = vec![RDB_TYPE_STREAM_LISTPACKS_3];
            body.extend_from_slice(&stream_payload);
            Ok(append_dump_footer(body))
        }

        let duplicate_payload = stream_dump_with_entries(vec![
            (1, 0, vec![(b"f".to_vec(), b"v1".to_vec())]),
            (1, 0, vec![(b"f".to_vec(), b"v2".to_vec())]),
        ])?;
        let mut duplicate_store = Store::new();
        match duplicate_store.restore_key(b"duplicate", 0, &duplicate_payload, false, 100) {
            Err(StoreError::InvalidDumpPayload) => {}
            other => {
                return Err(format!(
                    "duplicate stream entry IDs should fail restore, got {other:?}"
                ));
            }
        }

        let valid_payload = stream_dump_with_entries(vec![
            (1, 0, vec![(b"f".to_vec(), b"v1".to_vec())]),
            (2, 0, vec![(b"f".to_vec(), b"v2".to_vec())]),
        ])?;
        let mut valid_store = Store::new();
        valid_store
            .restore_key(b"valid", 0, &valid_payload, false, 100)
            .map_err(|err| format!("valid stream entry IDs must restore: {err:?}"))?;

        Ok(())
    }

    #[test]
    fn dump_restore_with_ttl() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"val".to_vec(), Some(200), 100);
        let payload = store.dump_key(b"k", 100).unwrap();
        let mut store2 = Store::new();
        // Restore with explicit TTL of 50ms
        store2.restore_key(b"k", 50, &payload, false, 100).unwrap();
        assert_eq!(store2.get(b"k", 100).unwrap(), Some(b"val".to_vec()));
        // After 50ms the key should be expired
        assert_eq!(store2.get(b"k", 151).unwrap(), None);
    }

    #[test]
    fn dump_restore_busy_key() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"old".to_vec(), None, 100);
        store.set(b"k2".to_vec(), b"val".to_vec(), None, 100);
        let payload = store.dump_key(b"k2", 100).unwrap();
        // Without REPLACE, should fail with BusyKey
        assert_eq!(
            store.restore_key(b"k", 0, &payload, false, 100),
            Err(StoreError::BusyKey)
        );
        // With REPLACE, should succeed
        store.restore_key(b"k", 0, &payload, true, 100).unwrap();
        assert_eq!(store.get(b"k", 100).unwrap(), Some(b"val".to_vec()));
    }

    #[test]
    fn dump_restore_invalid_crc_rejected() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 100);
        let mut payload = store.dump_key(b"k", 100).unwrap();
        // Corrupt the CRC bytes
        let last = payload.len() - 1;
        payload[last] ^= 0xFF;
        let mut store2 = Store::new();
        assert_eq!(
            store2.restore_key(b"k", 0, &payload, false, 100),
            Err(StoreError::InvalidDumpPayload)
        );
    }

