    #[test]
    fn aof_commands_sorted_set_key() {
        let mut store = Store::new();
        store
            .zadd(
                b"myzset",
                &[(1.5, b"alice".to_vec()), (2.0, b"bob".to_vec())],
                100,
            )
            .unwrap();
        let cmds = store.to_aof_commands(100);
        assert_eq!(cmds.len(), 2);
        assert_eq!(cmds[0], vec![b"SELECT".to_vec(), b"0".to_vec()]);
        assert_eq!(cmds[1][0], b"ZADD");
        assert_eq!(cmds[1][1], b"myzset");
        // Score-member pairs sorted by score then member
        assert_eq!(cmds[1].len(), 6); // ZADD key score1 member1 score2 member2
    }

    fn expect_aof_command_shapes(
        cmds: &[Vec<Vec<u8>>],
        expected: &[(&[u8], usize)],
    ) -> Result<(), String> {
        let mut actual = cmds.iter();
        for (expected_name, expected_len) in expected {
            let Some(cmd) = actual.next() else {
                return Err("missing AOF command".into());
            };
            let Some(name) = cmd.first() else {
                return Err("empty AOF command".into());
            };
            if !super::eq_ascii_ci(name, expected_name) {
                return Err("AOF command name mismatch".into());
            }
            match cmd.len().cmp(expected_len) {
                std::cmp::Ordering::Equal => {}
                _ => return Err("AOF command length mismatch".into()),
            }
        }
        if actual.next().is_some() {
            return Err("unexpected extra AOF command".into());
        }
        Ok(())
    }

    #[test]
    fn aof_commands_collection_batches_at_upstream_limit() -> Result<(), String> {
        let mut store = Store::new();
        let list_items: Vec<Vec<u8>> = (0u8..65).map(|idx| vec![b'l', idx]).collect();
        if store.rpush(b"list", &list_items, 100).is_err() {
            return Err("rpush failed".into());
        }
        let cmds = store.to_aof_commands(100);
        expect_aof_command_shapes(
            &cmds,
            &[
                (b"SELECT".as_slice(), 2),
                (b"RPUSH".as_slice(), 66),
                (b"RPUSH".as_slice(), 3),
            ],
        )?;

        let mut store = Store::new();
        for idx in 0u8..65 {
            if store
                .hset(b"hash", vec![b'f', idx], vec![b'v', idx], 100)
                .is_err()
            {
                return Err("hset failed".into());
            }
        }
        let cmds = store.to_aof_commands(100);
        expect_aof_command_shapes(
            &cmds,
            &[
                (b"SELECT".as_slice(), 2),
                (b"HMSET".as_slice(), 130),
                (b"HMSET".as_slice(), 4),
            ],
        )?;

        let mut store = Store::new();
        let set_items: Vec<Vec<u8>> = (0u8..65).map(|idx| vec![b's', idx]).collect();
        if store.sadd(b"set", &set_items, 100).is_err() {
            return Err("sadd failed".into());
        }
        let cmds = store.to_aof_commands(100);
        expect_aof_command_shapes(
            &cmds,
            &[
                (b"SELECT".as_slice(), 2),
                (b"SADD".as_slice(), 66),
                (b"SADD".as_slice(), 3),
            ],
        )?;

        let mut store = Store::new();
        let zset_items: Vec<(f64, Vec<u8>)> = (0u8..65)
            .map(|idx| (f64::from(idx), vec![b'z', idx]))
            .collect();
        if store.zadd(b"zset", &zset_items, 100).is_err() {
            return Err("zadd failed".into());
        }
        let cmds = store.to_aof_commands(100);
        expect_aof_command_shapes(
            &cmds,
            &[
                (b"SELECT".as_slice(), 2),
                (b"ZADD".as_slice(), 130),
                (b"ZADD".as_slice(), 4),
            ],
        )?;
        Ok(())
    }

    #[test]
    fn aof_commands_stream_key() -> Result<(), String> {
        let mut store = Store::new();
        store
            .xadd(
                b"mystream",
                (1000, 0),
                &[(b"name".to_vec(), b"val".to_vec())],
                100,
            )
            .map_err(|err| format!("xadd failed: {err:?}"))?;
        let cmds = store.to_aof_commands(100);
        let mut commands = cmds.iter();
        let Some(select) = commands.next() else {
            return Err("missing SELECT".into());
        };
        let Some(xadd) = commands.next() else {
            return Err("missing XADD".into());
        };
        let Some(_xsetid) = commands.next() else {
            return Err("missing XSETID".into());
        };
        if commands.next().is_some() {
            return Err("unexpected extra stream AOF command".into());
        }
        if select != &vec![b"SELECT".to_vec(), b"0".to_vec()] {
            return Err("stream AOF must select DB 0 before XADD".into());
        }
        match xadd.len().cmp(&5) {
            std::cmp::Ordering::Equal => {}
            _ => return Err("stream XADD argument count mismatch".into()),
        }
        for (actual, expected) in xadd.iter().zip([
            b"XADD".as_slice(),
            b"mystream".as_slice(),
            b"1000-0".as_slice(),
            b"name".as_slice(),
            b"val".as_slice(),
        ]) {
            if !super::eq_ascii_ci(actual, expected) {
                return Err("stream XADD argument mismatch".into());
            }
        }
        Ok(())
    }

    #[test]
    fn aof_commands_empty_stream_uses_upstream_placeholder() -> Result<(), String> {
        let mut store = Store::new();
        store
            .xgroup_create(b"s", b"g", (0, 0), true, 100)
            .map_err(|err| format!("xgroup create failed: {err:?}"))?;

        let cmds = store.to_aof_commands(100);
        let expected = [
            (
                "SELECT",
                vec![
                    (b"SELECT".as_slice(), "command"),
                    (b"0".as_slice(), "db index"),
                ],
            ),
            (
                "placeholder XADD",
                vec![
                    (b"XADD".as_slice(), "command"),
                    (b"s".as_slice(), "key"),
                    (b"MAXLEN".as_slice(), "trim keyword"),
                    (b"0".as_slice(), "trim length"),
                    (b"0-1".as_slice(), "placeholder id"),
                    (b"x".as_slice(), "placeholder field"),
                    (b"y".as_slice(), "placeholder value"),
                ],
            ),
            (
                "XSETID",
                vec![
                    (b"XSETID".as_slice(), "command"),
                    (b"s".as_slice(), "key"),
                    (b"0-0".as_slice(), "last id"),
                    (b"ENTRIESADDED".as_slice(), "entries keyword"),
                    (b"0".as_slice(), "entries count"),
                    (b"MAXDELETEDID".as_slice(), "deleted keyword"),
                    (b"0-0".as_slice(), "deleted id"),
                ],
            ),
            (
                "XGROUP CREATE",
                vec![
                    (b"XGROUP".as_slice(), "command"),
                    (b"CREATE".as_slice(), "subcommand"),
                    (b"s".as_slice(), "key"),
                    (b"g".as_slice(), "group"),
                    (b"0-0".as_slice(), "last id"),
                    (b"ENTRIESREAD".as_slice(), "entries-read keyword"),
                    (b"-1".as_slice(), "default entries-read"),
                ],
            ),
        ];

        match cmds.len().cmp(&expected.len()) {
            std::cmp::Ordering::Equal => {}
            _ => {
                return Err(format!(
                    "empty stream emitted {} commands, expected {}",
                    cmds.len(),
                    expected.len()
                ));
            }
        }
        for (actual, (command_name, expected_args)) in cmds.iter().zip(expected.iter()) {
            match actual.len().cmp(&expected_args.len()) {
                std::cmp::Ordering::Equal => {}
                _ => {
                    return Err(format!(
                        "{command_name} has {} args, expected {}",
                        actual.len(),
                        expected_args.len()
                    ));
                }
            }
            for (actual_arg, (expected_arg, label)) in actual.iter().zip(expected_args.iter()) {
                if !super::eq_ascii_ci(actual_arg, expected_arg) {
                    return Err(format!(
                        "{command_name} {label} was {:?}",
                        String::from_utf8_lossy(actual_arg)
                    ));
                }
            }
        }
        Ok(())
    }

    #[test]
    fn aof_commands_stream_with_xsetid() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1, 0), &[(b"k".to_vec(), b"v".to_vec())], 100)
            .unwrap();
        // XSETID sets a last-generated-id higher than any entry
        store.xsetid(b"s", (999, 0), 100).unwrap();
        let cmds = store.to_aof_commands(100);
        // XADD + XSETID
        assert_eq!(cmds.len(), 3);
        assert_eq!(cmds[0], vec![b"SELECT".to_vec(), b"0".to_vec()]);
        assert_eq!(cmds[1][0], b"XADD");
        assert_eq!(cmds[2][0], b"XSETID");
        assert_eq!(cmds[2][1], b"s");
        assert_eq!(cmds[2][2], b"999-0");
        assert_eq!(cmds[2][3], b"ENTRIESADDED");
        assert_eq!(cmds[2][4], b"1");
    }

    #[test]
    fn aof_commands_stream_preserves_xsetid_entriesadded() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1, 0), &[(b"k".to_vec(), b"v".to_vec())], 100)
            .unwrap();
        store
            .xsetid_with_metadata(b"s", (1, 0), Some(10), None, 100)
            .unwrap();

        let cmds = store.to_aof_commands(100);
        assert_eq!(cmds.len(), 3);
        assert_eq!(cmds[0], vec![b"SELECT".to_vec(), b"0".to_vec()]);
        assert_eq!(cmds[2][0], b"XSETID");
        assert_eq!(cmds[2][1], b"s");
        assert_eq!(cmds[2][2], b"1-0");
        assert_eq!(cmds[2][3], b"ENTRIESADDED");
        assert_eq!(cmds[2][4], b"10");
    }

    #[test]
    fn aof_commands_stream_with_consumer_group() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1, 0), &[(b"k".to_vec(), b"v".to_vec())], 100)
            .unwrap();
        store
            .xgroup_create_with_entries_read(b"s", b"grp1", (0, 0), Some(0), false, 100)
            .unwrap();
        store
            .xgroup_create(b"s", b"grp2", (1, 0), false, 100)
            .unwrap();
        let cmds = store.to_aof_commands(100);
        // XADD + XSETID + 2x XGROUP CREATE, matching Redis AOF rewrite.
        assert_eq!(cmds.len(), 5);
        assert_eq!(cmds[0], vec![b"SELECT".to_vec(), b"0".to_vec()]);
        assert_eq!(cmds[1][0], b"XADD");
        // Groups sorted by name
        assert_eq!(cmds[3][0], b"XGROUP");
        assert_eq!(cmds[3][1], b"CREATE");
        assert_eq!(cmds[3][2], b"s");
        assert_eq!(cmds[3][3], b"grp1");
        assert_eq!(cmds[3][4], b"0-0");
        assert_eq!(cmds[3][5], b"ENTRIESREAD");
        assert_eq!(cmds[3][6], b"0");
        assert_eq!(
            cmds[4],
            vec![
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"grp2".to_vec(),
                b"1-0".to_vec(),
                b"ENTRIESREAD".to_vec(),
                b"-1".to_vec(),
            ]
        );
    }

    #[test]
    fn aof_commands_stream_with_consumers_and_pending_entries() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1, 0), &[(b"k".to_vec(), b"v".to_vec())], 100)
            .unwrap();
        assert!(store.xgroup_create(b"s", b"g", (0, 0), false, 100).unwrap());
        assert_eq!(
            store
                .xgroup_createconsumer(b"s", b"g", b"idle", 110)
                .expect("group must exist"),
            Some(true)
        );
        store
            .xreadgroup(
                b"s",
                b"g",
                b"alice",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(1)),
                120,
            )
            .expect("pending seed")
            .expect("group must exist");
        let _ = store
            .xclaim(
                b"s",
                b"g",
                b"bob",
                &[(1, 0)],
                StreamClaimOptions {
                    min_idle_time_ms: 0,
                    idle_ms: None,
                    time_ms: Some(250),
                    retry_count: Some(7),
                    force: false,
                    justid: false,
                    last_id: None,
                },
                130,
            )
            .expect("xclaim must succeed");

        let cmds = store.to_aof_commands(100);
        assert_eq!(cmds.len(), 7);
        assert_eq!(cmds[0], vec![b"SELECT".to_vec(), b"0".to_vec()]);
        assert_eq!(cmds[1][0], b"XADD");
        // XGROUP CREATE replay carries the ENTRIESREAD trailer so the
        // restored group preserves its read counter. (frankenredis-ic8v)
        assert_eq!(
            cmds[3],
            vec![
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"1-0".to_vec(),
                b"ENTRIESREAD".to_vec(),
                b"1".to_vec(),
            ]
        );
        assert_eq!(
            cmds[4],
            vec![
                b"XGROUP".to_vec(),
                b"CREATECONSUMER".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"alice".to_vec(),
            ]
        );
        assert_eq!(
            cmds[5],
            vec![
                b"XCLAIM".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"bob".to_vec(),
                b"0".to_vec(),
                b"1-0".to_vec(),
                b"TIME".to_vec(),
                b"250".to_vec(),
                b"RETRYCOUNT".to_vec(),
                b"7".to_vec(),
                b"JUSTID".to_vec(),
                b"FORCE".to_vec(),
            ]
        );
        assert_eq!(
            cmds[6],
            vec![
                b"XGROUP".to_vec(),
                b"CREATECONSUMER".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"idle".to_vec(),
            ]
        );
    }

