        let mut store = Store::new();
        store.set(b"z_key".to_vec(), b"1".to_vec(), None, 100);
        store.set(b"a_key".to_vec(), b"2".to_vec(), None, 100);
        store.set(b"m_key".to_vec(), b"3".to_vec(), None, 100);
